export interface FacialFeatures {
  eyeSize: number;
  lipThickness: number;
  noseWidth: number;
  eyelidType: 'Monolid' | 'Double' | 'Hooded';
  jawlineSharpness: number;
  canthalTilt: number; // eyeTilt
  jawShape: number;
  cheekboneHeight: number;
  faceWidth: number;
  eyeDistance: number;
  noseBridge: number;
  mouthCorners: number;
  lipCupidBow: number;
}

export interface SkinFeatures {
  tone: string;
  texture: string[];
  skinAge: number;
  glowIntensity: number;
  blemishIntensity: number;
}

export interface HairFeatures {
  hairStyle: string;
  hairLength: 'pixie' | 'bob' | 'shoulder' | 'long' | 'extra_long';
  hairTexture: 'straight' | 'c_curl' | 'waves' | 'curly' | 'hippie';
  bangStyle: 'none' | 'see_through' | 'full_blunt' | 'curtain';
  hairVolume: number;
  hairShine: number;
  hairColorTop: string;
  hairColorBottom: string;
  hairColorBoundary: number;
}

export interface MakeupFeatures {
  makeupStyle: string;
  eyebrowStyle: 'arched' | 'straight' | 'bushy';
  eyelinerStyle: 'none' | 'thin' | 'winged' | 'smudged';
  eyelashStyle: 'natural' | 'mascara' | 'idol_lashes' | 'false_lashes';
