import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { StudioSidebar } from './components/StudioSidebar';
import { PreviewCanvas } from './components/PreviewCanvas';
import { ApiKeyModal } from './components/ApiKeyModal';
import { generateBeautyImage, generateBeautyPrompt, analyzeImageAttributes } from './services/geminiService';
import { BeautyState } from './types';
import { INITIAL_FEATURES, INITIAL_HAIR, INITIAL_MAKEUP } from './constants';
import { Sparkles, Upload, Trash2, Zap, Eye, EyeOff, Download, RefreshCcw, Search } from 'lucide-react';

const App: React.FC = () => {
  const [state, setState] = useState<BeautyState>({
    baseImage: null,
    referenceImages: {
      face: null,
      skin: null,
      hair: null,
      makeup: null
    },
    features: INITIAL_FEATURES,
    skin: { 
      tone: 'natural', 
      texture: ['Smooth'],
      skinAge: 20,
      glowIntensity: 50,
      blemishIntensity: 10
    },
    hair: INITIAL_HAIR,
    makeup: INITIAL_MAKEUP,
    customPrompts: {
      face: '',
      skin: '',
      hair: '',
      makeup: ''
    },
    editModes: {
      face: false,
      skin: false,
      hair: false,
      makeup: false
    },
    aspectRatio: '1:1',
    baseline: undefined
  });

  const [isGenerating, setIsGenerating] = useState(false);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [generatedImage, setGeneratedImage] = useState<string | null>(null);
  const [needsKey, setNeedsKey] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isComparing, setIsComparing] = useState(false);

  useEffect(() => {
    const checkKey = async () => {
      if (window.aistudio) {
        const hasKey = await window.aistudio.hasSelectedApiKey();
        setNeedsKey(!hasKey);
      }
    };
    checkKey();
  }, []);

  const applyAnalysis = (data: any) => {
    const skinToneId = data.skinTone < 20 ? 'porcelain' 
                     : data.skinTone < 40 ? 'fair' 
                     : data.skinTone < 60 ? 'natural' 
                     : data.skinTone < 80 ? 'tanned' 
                     : 'deep';

    const hairLen = data.hairLength === 'short' ? 'bob' : data.hairLength === 'medium' ? 'shoulder' : 'long';
    const hairTex = data.hairTexture === 'straight' ? 'straight' : 'waves';

    // 분석 데이터 맵핑 및 누락된 필드는 50(중앙값)으로 채움
    const analyzedFeatures = {
      ...INITIAL_FEATURES,
      eyeSize: data.eyeSize ?? 50,
      canthalTilt: data.eyeTilt ?? 50,
      noseBridge: data.noseBridge ?? 50,
      noseWidth: data.noseWidth ?? 50,
      faceWidth: data.faceWidth ?? 50,
      cheekboneHeight: data.cheekboneHeight ?? 50,
      jawShape: data.jawShape ?? 50,
      lipThickness: data.lipFullness ?? 50,
    };

    setState(prev => ({
      ...prev,
      features: analyzedFeatures,
      skin: {
        ...prev.skin,
        tone: skinToneId,
        skinAge: data.skinAge ?? 20,
      },
      hair: {
        ...prev.hair,
        hairLength: hairLen,
        hairTexture: hairTex,
      },
      baseline: {
        features: analyzedFeatures,
        skin: {
          tone: skinToneId,
          skinAge: data.skinAge ?? 20,
        },
        hair: {
          hairLength: hairLen,
          hairTexture: hairTex
        }
      }
    }));
  };

  const resetCategory = useCallback((category: 'face' | 'skin' | 'hair' | 'makeup') => {
    setState(prev => {
      const newState = { ...prev };
      const bl = prev.baseline;

      switch (category) {
        case 'face':
          newState.features = {
            ...INITIAL_FEATURES,
            ...(bl?.features || {})
          };
          newState.makeup = {
            ...prev.makeup,
            eyebrowStyle: INITIAL_MAKEUP.eyebrowStyle,
            eyelinerStyle: INITIAL_MAKEUP.eyelinerStyle,
            eyelashStyle: INITIAL_MAKEUP.eyelashStyle
          };
          newState.customPrompts = { ...prev.customPrompts, face: '' };
          break;
        case 'skin':
          newState.skin = {
            ...prev.skin,
            tone: bl?.skin?.tone || 'natural',
            skinAge: bl?.skin?.skinAge || 20,
            glowIntensity: 50,
            blemishIntensity: 10,
            texture: ['Smooth']
          };
          newState.customPrompts = { ...prev.customPrompts, skin: '' };
          break;
        case 'hair':
          newState.hair = {
            ...INITIAL_HAIR,
            hairLength: bl?.hair?.hairLength || INITIAL_HAIR.hairLength,
            hairTexture: bl?.hair?.hairTexture || INITIAL_HAIR.hairTexture
          };
          newState.customPrompts = { ...prev.customPrompts, hair: '' };
          break;
        case 'makeup':
          newState.makeup = {
            ...INITIAL_MAKEUP,
            eyebrowStyle: prev.makeup.eyebrowStyle,
            eyelinerStyle: prev.makeup.eyelinerStyle,
            eyelashStyle: prev.makeup.eyelashStyle
          };
          newState.customPrompts = { ...prev.customPrompts, makeup: '' };
          break;
      }
      return newState;
    });
  }, []);

  const handleGenerate = async () => {
    try {
      setIsGenerating(true);
      setError(null);
      const result = await generateBeautyImage(state);
      if (result) {
        setGeneratedImage(result);
      } else {
        setError("Synthesis failed. Please check your settings and try again.");
      }
    } catch (err: any) {
      if (err.message?.includes("Requested entity was not found")) {
        setNeedsKey(true);
      }
      setError(err.message || "An error occurred during synthesis.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleDownload = () => {
    if (!generatedImage) return;
    const link = document.createElement('a');
    link.href = generatedImage;
    link.download = `BeautySynth_PRO_2K_${Date.now()}.png`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleUseAsBase = () => {
    if (!generatedImage) return;
    updateState({ 
      baseImage: generatedImage,
      baseline: undefined 
    });
    setGeneratedImage(null);
    setIsComparing(false);
  };

  const updateState = (updates: Partial<BeautyState>) => {
    setState(prev => ({ ...prev, ...updates }));
  };

  const calculateAspectRatio = (img: HTMLImageElement): "1:1" | "3:4" | "4:3" | "9:16" | "16:9" => {
    const ratio = img.width / img.height;
    const options: { label: "1:1" | "3:4" | "4:3" | "9:16" | "16:9", value: number }[] = [
      { label: "1:1", value: 1 },
      { label: "3:4", value: 0.75 },
      { label: "4:3", value: 1.33 },
      { label: "9:16", value: 0.5625 },
      { label: "16:9", value: 1.777 }
    ];
    return options.reduce((prev, curr) => Math.abs(curr.value - ratio) < Math.abs(prev.value - ratio) ? curr : prev).label;
  };

  const onFileUpload = (type: 'base' | 'face' | 'skin' | 'hair' | 'makeup') => (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = reader.result as string;
        if (type === 'base') {
          const img = new Image();
          img.onload = async () => {
            const ratio = calculateAspectRatio(img);
            updateState({ baseImage: base64String, aspectRatio: ratio, baseline: undefined });

            try {
              setIsAnalyzing(true);
              const analysis = await analyzeImageAttributes(base64String);
              applyAnalysis(analysis);
            } catch (err) {
              console.error("AI Analysis failed:", err);
              setError("AI analysis failed. Please adjust features manually.");
            } finally {
              setIsAnalyzing(false);
            }
          };
          img.src = base64String;
        } else {
          updateState({ 
            referenceImages: { 
              ...state.referenceImages, 
              [type]: base64String 
            } 
          });
        }
      };
      reader.readAsDataURL(file);
    }
  };

  const currentPrompt = useMemo(() => generateBeautyPrompt(state), [state]);

  if (needsKey) {
    return <ApiKeyModal onComplete={() => setNeedsKey(false)} />;
  }

  return (
    <div className="flex flex-col h-screen bg-black overflow-hidden text-zinc-100">
      <header className="h-16 border-b border-zinc-900 flex items-center justify-between px-6 bg-zinc-950/80 backdrop-blur-xl z-50">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center shadow-lg shadow-indigo-500/20">
            <Sparkles className="w-6 h-6 text-white" />
          </div>
          <div>
            <h1 className="text-lg font-bold tracking-tight">BeautySynth <span className="text-indigo-500">PRO</span></h1>
            <p className="text-[10px] text-zinc-500 font-bold uppercase tracking-widest">Expert Medical Facial Synthesis</p>
          </div>
        </div>

        <div className="flex items-center gap-4">
          <button 
            onClick={handleGenerate}
            disabled={isGenerating || !state.baseImage}
            className={`flex items-center gap-2 px-8 py-2.5 rounded-full font-bold transition-all ${
              isGenerating || !state.baseImage
              ? 'bg-zinc-900 text-zinc-600 cursor-not-allowed opacity-50' 
              : 'bg-indigo-600 hover:bg-indigo-500 text-white active:scale-95 shadow-xl shadow-indigo-600/20'
            }`}
          >
            {isGenerating ? (
              <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" />
            ) : <Zap className="w-4 h-4 fill-current" />}
            {isGenerating ? 'Synthesizing (2K)...' : 'Generate Synthesis'}
          </button>
        </div>
      </header>

      <main className="flex flex-1 overflow-hidden">
        <StudioSidebar 
          state={state} 
          updateState={updateState} 
          onRefUpload={onFileUpload} 
          onResetCategory={resetCategory}
        />

        <div className="flex-1 p-6 flex flex-col gap-6 overflow-hidden bg-zinc-950">
          {error && (
            <div className="bg-red-500/10 border border-red-500/20 text-red-400 p-3 rounded-xl flex items-center justify-between text-sm shrink-0">
              <span>{error}</span>
              <button onClick={() => setError(null)}>✕</button>
            </div>
          )}

          <div className="flex flex-col flex-1 min-h-0 gap-6">
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 flex-1 min-h-0">
              <div className="bg-zinc-900/50 border border-zinc-800/50 rounded-3xl overflow-hidden flex flex-col relative group shadow-inner">
                <div className="p-4 border-b border-zinc-800/50 flex justify-between items-center bg-zinc-900/30">
                  <h3 className="text-[10px] font-bold text-zinc-500 uppercase tracking-widest">Input: Base Image</h3>
                  <div className="flex items-center gap-2">
                    {isAnalyzing && (
                      <span className="text-[10px] font-bold text-indigo-400 animate-pulse flex items-center gap-1">
                        <Search className="w-3 h-3" /> AI Analyzing...
                      </span>
                    )}
                    {state.baseImage && (
                      <button onClick={() => updateState({ baseImage: null, baseline: undefined })} className="text-zinc-600 hover:text-red-400">
                        <Trash2 className="w-4 h-4" />
                      </button>
                    )}
                  </div>
                </div>
                <div className="flex-1 flex items-center justify-center relative bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-zinc-900 to-black overflow-hidden">
                  {state.baseImage ? (
                    <>
                      <img src={state.baseImage} className={`max-w-full max-h-full object-contain transition-opacity duration-500 ${isAnalyzing ? 'opacity-40 grayscale' : 'opacity-100'}`} alt="Base" />
                      {isAnalyzing && (
                        <div className="absolute inset-0 flex flex-col items-center justify-center pointer-events-none">
                           <div className="w-full h-1 bg-indigo-500/30 overflow-hidden absolute top-0">
                              <div className="w-1/3 h-full bg-indigo-500 animate-[scan_2s_linear_infinite]" />
                           </div>
                           <div className="bg-black/60 backdrop-blur-md px-4 py-2 rounded-full border border-indigo-500/30 shadow-2xl flex items-center gap-2">
                             <div className="w-3 h-3 border-2 border-indigo-500 border-t-transparent rounded-full animate-spin" />
                             <span className="text-xs font-bold text-indigo-400 uppercase tracking-widest">Extracting Features</span>
                           </div>
                        </div>
                      )}
                    </>
                  ) : (
                    <label className="cursor-pointer flex flex-col items-center gap-4">
                      <div className="w-20 h-20 rounded-full bg-zinc-800 flex items-center justify-center text-zinc-500 hover:text-indigo-400 transition-colors border border-zinc-700">
                        <Upload className="w-8 h-8" />
                      </div>
                      <span className="text-zinc-500 font-medium text-sm">Upload Base Image</span>
                      <input type="file" className="hidden" accept="image/*" onChange={onFileUpload('base')} />
                    </label>
                  )}
                </div>
              </div>

              <div className="bg-zinc-900/50 border border-zinc-800/50 rounded-3xl overflow-hidden flex flex-col relative shadow-2xl">
                <div className="p-4 border-b border-zinc-800/50 flex justify-between items-center bg-zinc-900/30">
                  <h3 className="text-[10px] font-bold text-zinc-500 uppercase tracking-widest">Synthesis Result: 2K UHD</h3>
                  <div className="flex gap-2">
                    {generatedImage && (
                      <>
                        <button 
                          onClick={handleUseAsBase}
                          className="text-[10px] font-bold uppercase tracking-widest text-indigo-400 flex items-center gap-2 px-3 py-1 rounded-full bg-indigo-500/10 border border-indigo-500/20 active:scale-95 transition-all hover:bg-indigo-500/20"
                          title="Use result as base"
                        >
                          <RefreshCcw className="w-3 h-3" />
                          Use as Base
                        </button>
                        <button 
                          onClick={handleDownload}
                          className="text-[10px] font-bold uppercase tracking-widest text-emerald-400 flex items-center gap-2 px-3 py-1 rounded-full bg-emerald-500/10 border border-emerald-500/20 active:scale-95 transition-all hover:bg-emerald-500/20"
                        >
                          <Download className="w-3 h-3" />
                          Download
                        </button>
                        <button 
                          onMouseDown={() => setIsComparing(true)}
                          onMouseUp={() => setIsComparing(false)}
                          onMouseLeave={() => setIsComparing(false)}
                          className="text-[10px] font-bold uppercase tracking-widest text-zinc-400 flex items-center gap-2 px-3 py-1 rounded-full bg-zinc-500/10 border border-zinc-500/20 active:scale-95 select-none transition-all hover:bg-zinc-500/20"
                        >
                          {isComparing ? <EyeOff className="w-3 h-3" /> : <Eye className="w-3 h-3" />}
                          Compare
                        </button>
                      </>
                    )}
                  </div>
                </div>
                <div className="flex-1 bg-black relative flex items-center justify-center group overflow-hidden">
                  <PreviewCanvas 
                    image={isComparing ? state.baseImage : generatedImage} 
                    loading={isGenerating}
                    onDownload={handleDownload}
                  />
                  {isComparing && (
                    <div className="absolute top-4 left-4 px-3 py-1 bg-black/80 text-[10px] font-bold text-white uppercase tracking-widest rounded-full border border-white/20">
                      Original
                    </div>
                  )}
                </div>
              </div>
            </div>

            <div className="bg-zinc-900/50 border border-zinc-800/50 rounded-3xl p-4 flex flex-col gap-2 shrink-0 h-28 shadow-inner overflow-hidden">
              <h3 className="text-[10px] font-bold text-zinc-500 uppercase tracking-widest flex items-center gap-2">
                <Zap className="w-3 h-3 text-indigo-500" /> Targeted Synthesis Prompt Preview
              </h3>
              <div className="flex-1 overflow-y-auto text-[11px] text-zinc-400 leading-relaxed font-mono bg-black/30 p-3 rounded-xl border border-zinc-800/50">
                {currentPrompt}
              </div>
            </div>
          </div>
        </div>
      </main>
      <style>{`
        @keyframes scan {
          from { transform: translateX(-100%); }
          to { transform: translateX(300%); }
        }
      `}</style>
    </div>
  );
};

export default App;

import { GoogleGenAI, Type } from "@google/genai";
import { BeautyState, FacialFeatures, SkinFeatures } from "../types";
import { SKIN_TONES, SKIN_TEXTURES, INITIAL_MAKEUP } from "../constants";

const getSliderAdjective = (value: number, type: string): string => {
  if (value >= 85) {
    switch (type) {
      case 'eyeSize': return "EXTREME enlargement; create a wide-eyed doll-like appearance with significantly larger irises";
      case 'lipThickness': return "MAXIMUM volume; perform massive vermilion border expansion for an extreme filler-injected look";
      case 'noseWidth': return "pronounced wide nasal base; broaden the nostrils for a strong, wide nose profile";
      case 'jawlineSharpness': return "ULTRA-DEFINED; create a razor-sharp, chiseled mandibular line that cuts through the profile";
      case 'canthalTilt': return "HYPER-FELINE; drastically elevate the lateral canthus for an extreme feline/cat-eye tilt";
      case 'jawShape': return "EXTREME V-LINE; aggressively taper the chin to a sharp point, drastically narrowing the lower third of the face";
      case 'cheekboneHeight': return "HIGH-FASHION SKELETAL PROJECTION; create dramatic, protruding zygomatic arches with deep hollows underneath";
      case 'faceWidth': return "CRANIAL EXPANSION; significantly increase the overall width of the facial structure and head shape";
      case 'eyeDistance': return "WIDE-SET AVATAR LOOK; significantly increase the interpupillary distance for a unique, wide-set appearance";
      case 'noseBridge': return "TALL ARCHITECTURE; raise the nasal bridge to a prominent, high-profile Grecian or Roman height";
      case 'mouthCorners': return "JOKER-LIKE UPTURN; create a permanent, deep upturn at the commissures for a smiling expression";
      case 'lipCupidBow': return "SURGICAL PRECISION; carve a very deep, sharp M-shaped cupid's bow with high peaks";
      case 'skinAge': return "ELDERLY CHARACTER; add realistic deep wrinkles, age spots, and sagging skin texture";
      case 'glowIntensity': return "OIL-SLICK SHINE; create a hyper-reflective, wet-look skin finish with blinding highlights";
      case 'blemishIntensity': return "RAW REALISM; add heavy freckles, visible pores, moles, and natural skin imperfections";
      case 'hairVolume': return "GRAVITY-DEFYING VOLUME; create massive root lift and a hyper-voluminous hair silhouette";
      case 'hairShine': return "HYPER-SILKY; provide a reflective, salon-quality mirror shine with zero frizz";
      case 'contourIntensity': return "EXTREME DRAG CONTOUR; apply very dark, sharp shadows to redefine the facial skeleton";
    }
  }
  if (value <= 15) {
    switch (type) {
      case 'eyeSize': return "MINIMALIST; significantly reduce eye size for a narrow, squinted, or hooded look";
      case 'lipThickness': return "PAPER-THIN; drastically reduce lip volume until the lips are nearly a straight line";
      case 'noseWidth': return "PINCHED RHINOPLASTY; extremely narrow the nasal ala and nostrils to a needle-thin point";
      case 'jawlineSharpness': return "SOFT INFANTILE; completely round out the jawline, removing all sharp angles for a soft, fleshy look";
      case 'canthalTilt': return "DEEP PUPPY-EYE; drastically lower the lateral corners for a sad, drooping, or sleepy aesthetic";
      case 'jawShape': return "BROAD RECTANGULAR; flatten and widen the chin and lower jaw for a very square, strong masculine base";
      case 'cheekboneHeight': return "FLAT MIDFACE; completely suppress the cheekbones for a smooth, flat-cheeked appearance";
      case 'faceWidth': return "ULTRA-NARROW; drastically compress the face width into an extremely slim, elongated oval";
      case 'eyeDistance': return "CLOSE-SET; minimize the space between the eyes until they are nearly touching the bridge";
      case 'noseBridge': return "FLAT PROFILE; remove the nasal bridge height completely for a button-nose or flat aesthetic";
      case 'mouthCorners': return "MELANCHOLIC DROOP; pull the corners of the mouth down into a deep, sad pout";
      case 'lipCupidBow': return "SMOOTH ARCH; remove the cupid's bow peaks for a rounded, flat upper lip line";
      case 'skinAge': return "FETAL SMOOTHNESS; remove every single pore and line for an impossibly smooth, blurred finish";
      case 'glowIntensity': return "ULTRA-MATTE; remove all light reflection for a flat, velvet-like, chalky skin finish";
      case 'blemishIntensity': return "PORCELAIN DOLL; remove all skin texture, marks, and pores for a perfect, synthetic look";
      case 'hairVolume': return "FLAT-IRONED; collapse all volume for a sleek, thin hair look that hugs the skull";
      case 'hairShine': return "DRY & MATTE; create a raw, unstyled, matte hair texture with no highlights";
      case 'contourIntensity': return "FLAT LIGHTING; remove all shadows from the face for a flat, overexposed appearance";
    }
  }

  return `modified ${type}`;
};

const getDiffFeaturePrompt = (current: number, baseline: number | undefined, type: string): string => {
  const isStructural = ['jawShape', 'faceWidth', 'cheekboneHeight', 'jawlineSharpness', 'noseBridge', 'noseWidth', 'eyeDistance'].includes(type);

  if (baseline === undefined) {
    return `PIXEL-LOCK: Strictly preserve original ${type} structure.`;
  }

  const diff = current - baseline;

  // 미세한 차이는 변형하지 않고 원본 보존
  if (Math.abs(diff) < 5) return `PIXEL-LOCK: Strictly preserve original ${type}.`;

  const direction = diff > 0 ? "increase/broaden/raise" : "decrease/narrow/lower";
  const adjective = getSliderAdjective(current, type);

  if (isStructural) {
    return `BONE RECONSTRUCTION: Physically ${direction} the skeletal structure of ${type}. BREAK THE ORIGINAL SILHOUETTE. Use ${adjective}.`;
  }
  return `MORPHING: ${direction} the ${type} to be ${adjective}.`;
};

export const analyzeImageAttributes = async (base64Image: string) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const [header, data] = base64Image.split(';base64,');
  const mimeType = header.split(':')[1];

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          { inlineData: { data, mimeType } },
          { text: "Analyze the facial features of the person in this image. Focus on bone structure (cheekbones, face width, nose width) to prevent distortion during synthesis. Return ONLY a JSON object." }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            skinTone: { type: Type.NUMBER },
            skinAge: { type: Type.NUMBER },
            eyeSize: { type: Type.NUMBER },
            eyeTilt: { type: Type.NUMBER },
            noseBridge: { type: Type.NUMBER },
            noseWidth: { type: Type.NUMBER },
            faceWidth: { type: Type.NUMBER },
            cheekboneHeight: { type: Type.NUMBER },
            jawShape: { type: Type.NUMBER },
            lipFullness: { type: Type.NUMBER },
            hairLength: { type: Type.STRING, enum: ["short", "medium", "long"] },
            hairTexture: { type: Type.STRING, enum: ["straight", "curly"] }
          },
          required: ["skinTone", "skinAge", "eyeSize", "eyeTilt", "noseBridge", "noseWidth", "faceWidth", "cheekboneHeight", "jawShape", "lipFullness", "hairLength", "hairTexture"]
        }
      }
    });

    return JSON.parse(response.text);
  } catch (error) {
    console.error("Attribute Analysis Error:", error);
    throw error;
  }
};

export const generateBeautyPrompt = (state: BeautyState): string => {
  const { features, skin, hair, makeup, editModes, baseline } = state;

  const activeCategories = Object.entries(editModes).filter(([_, active]) => active).map(([name]) => name);
  const isTargetedEdit = activeCategories.length > 0;

  let faceInstruction = "";
  if (isTargetedEdit && !editModes.face) {
    // 헤어만 선택했을 때 얼굴형 보존을 위한 강력한 명령
    faceInstruction = "STRICT PIXEL-LOCK: DO NOT change the face shape, jawline, cheekbones, eyes, nose, or mouth. Keep the original facial structure 100% identical. No aesthetic enhancements to the face allowed.";
  } else if (!isTargetedEdit || editModes.face) {
    const modifications: string[] = [];
    const preservations: string[] = [];
    const featureKeys = ['eyeSize', 'canthalTilt', 'noseBridge', 'lipThickness', 'noseWidth', 'jawlineSharpness', 'cheekboneHeight', 'faceWidth', 'eyeDistance', 'mouthCorners', 'lipCupidBow', 'jawShape'];

    featureKeys.forEach(key => {
      const current = (features as any)[key];
      const bl = (baseline?.features as any)?.[key];
      const instruction = getDiffFeaturePrompt(current, bl, key);

      if (instruction.includes("PIXEL-LOCK")) preservations.push(instruction);
      else modifications.push(instruction);
    });

    faceInstruction = `
      SURGICAL TARGETS (FORCE CHANGE): ${modifications.length > 0 ? modifications.join(" | ") : "None"}.
      PIXEL ANCHORS (PROTECT): ${preservations.join(" | ")}.
      ${modifications.some(m => m.includes("BONE")) ? "CRITICAL OVERRIDE: Break the original silhouette for requested bone changes." : ""}
    `;
  }

  let skinInstruction = (isTargetedEdit && !editModes.skin) 
    ? "PIXEL-LOCK SKIN: Do not change the original skin tone, texture, or marks at all."
    : `RETEXTURE SKIN: Apply ${SKIN_TONES.find(t => t.id === skin.tone)?.prompt}. Texture: ${skin.texture.map(t => SKIN_TEXTURES.find(st => st.id === t)?.prompt).join(", ")}. Glow=${skin.glowIntensity}%, Age=${skin.skinAge}%, Imperfections=${skin.blemishIntensity}%.`;

  let hairInstruction = (isTargetedEdit && !editModes.hair)
    ? "PIXEL-LOCK HAIR: Preserve the original hairstyle, volume, and color perfectly."
    : `RECONSTRUCT HAIR: Style as ${hair.hairLength}, ${hair.hairTexture}. Volume=${hair.hairVolume}%, Shine/Gloss=${hair.hairShine}%. Gradient transition: Start with ${hair.hairColorTop} at roots, switching to ${hair.hairColorBottom} at exactly the ${hair.hairColorBoundary}% point from the top. ${getSliderAdjective(hair.hairShine, 'hairShine')}.`;

  let makeupInstruction = (isTargetedEdit && !editModes.makeup)
    ? "PIXEL-LOCK MAKEUP: Do not add or remove any makeup from the original image."
    : `APPLICATION: Apply ${makeup.makeupStyle} style. Eyeshadow: ${makeup.eyeshadowColor}, Blush: ${makeup.blushColor}, Lips: ${makeup.lipColor} (${makeup.lipStyle}).`;

  return `Act as a world-class High-End Digital Plastic Surgeon and Editorial Retoucher.

    CORE MANDATE: 
    - If a specific mode is set to PIXEL-LOCK, you MUST NOT change that area.
    - Only perform aggressive reshaping on specified SURGICAL TARGETS.

    TRANSFORMATION DIRECTIVES:
    - FACE SHAPE & FEATURES: ${faceInstruction}
    - DERMATOLOGY: ${skinInstruction}
    - HAIR ARTISTRY: ${hairInstruction}
    - MAKEUP ARTISTRY: ${makeupInstruction}

    TECHNICAL SPECS:
    - Quality: 2K Ultra HD, Cinema grade lighting.
    - Consistency: Maintain the exact lighting and background of the INPUT BASE IMAGE.`;
};

export const generateBeautyImage = async (state: BeautyState): Promise<string | null> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = generateBeautyPrompt(state);
  const parts: any[] = [{ text: prompt }];

  if (state.baseImage) {
    const baseData = state.baseImage.split(',')[1];
    const mimeType = state.baseImage.split(';')[0].split(':')[1];
    parts.push({ text: "INPUT BASE IMAGE" });
    parts.push({ inlineData: { data: baseData, mimeType } });
  }

  if (state.editModes.hair && state.referenceImages.hair) {
    const data = state.referenceImages.hair.split(',')[1];
    const mimeType = state.referenceImages.hair.split(';')[0].split(':')[1];
    parts.push({ text: "STYLE REFERENCE (HAIR)" });
    parts.push({ inlineData: { data, mimeType } });
  }

  if (state.editModes.makeup && state.referenceImages.makeup) {
    const data = state.referenceImages.makeup.split(',')[1];
    const mimeType = state.referenceImages.makeup.split(';')[0].split(':')[1];
    parts.push({ text: "STYLE REFERENCE (MAKEUP)" });
    parts.push({ inlineData: { data, mimeType } });
  }

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-image-preview',
      contents: { parts },
      config: {
        imageConfig: {
          aspectRatio: state.aspectRatio,
          imageSize: "2K"
        }
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
      }
    }
    return null;
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

