import { GoogleGenAI, Type } from "@google/genai";
import { BeautyState, FacialFeatures, SkinFeatures } from "../types";
import { SKIN_TONES, SKIN_TEXTURES, INITIAL_MAKEUP } from "../constants";

// [NEW] 속눈썹/눈썹 등 상세 묘사를 위한 헬퍼 맵
const STYLE_DESCRIPTIONS: Record<string, string> = {
  // Eyelashes
  'natural': 'natural length eyelashes',
  'mascara': 'long, defined, separated lashes with black mascara',
  'idol_lashes': 'K-pop style idol lashes, distinctively grouped/clumped spikes, dolly look',
  'false_lashes': 'thick, voluminous false eyelashes, dramatic eye look',
  // Eyebrows
  'arched': 'cleanly arched, high-fashion eyebrows',
  'straight': 'Korean style straight, soft eyebrows',
  'bushy': 'natural, wild, textured bushy eyebrows',
  // Eyeliner
  'none': 'no eyeliner',
  'thin': 'thin, subtle tightline eyeliner',
  'winged': 'sharp, upward winged eyeliner (cat-eye)',
  'smudged': 'softly smudged, smoky eyeliner'
};

const getSliderAdjective = (value: number, type: string): string => {
  if (value >= 85) {
    switch (type) {
      case 'eyeSize': return "EXTREME enlargement; create a wide-eyed doll-like appearance with significantly larger irises";
