const getDiffFeaturePrompt = (current: number, baseline: number | undefined, type: string): string => {
  const isStructural = ['jawShape', 'faceWidth', 'cheekboneHeight', 'jawlineSharpness', 'noseBridge', 'noseWidth', 'eyeDistance'].includes(type);

  if (baseline === undefined) {
    return `PIXEL-LOCK: Strictly preserve original ${type} structure.`;
  }

  const diff = current - baseline;

  // 미세한 차이는 무시 (Diff Logic)
  if (Math.abs(diff) < 5) return `PIXEL-LOCK: Strictly preserve original ${type}.`;

  const direction = diff > 0 ? "increase/broaden/raise" : "decrease/narrow/lower";
  const adjective = getSliderAdjective(current, type);

  if (isStructural) {
    return `BONE RECONSTRUCTION: Physically ${direction} the skeletal structure of ${type}. BREAK THE ORIGINAL SILHOUETTE. Use ${adjective}.`;
  }
  return `MORPHING: ${direction} the ${type} to be ${adjective}.`;
};

export const analyzeImageAttributes = async (base64Image: string) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const [header, data] = base64Image.split(';base64,');
  const mimeType = header.split(':')[1];

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.0-flash-exp', 
      contents: {
        parts: [
          { inlineData: { data, mimeType } },
          { text: "Analyze the facial features of the person in this image. Focus on bone structure (cheekbones, face width, nose width) to prevent distortion. Return ONLY a JSON object." }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            skinTone: { type: Type.NUMBER },
            skinAge: { type: Type.NUMBER },
            eyeSize: { type: Type.NUMBER },
            eyeTilt: { type: Type.NUMBER },
            noseBridge: { type: Type.NUMBER },
            noseWidth: { type: Type.NUMBER },       
            faceWidth: { type: Type.NUMBER },       
            cheekboneHeight: { type: Type.NUMBER }, 
            jawShape: { type: Type.NUMBER },
            lipFullness: { type: Type.NUMBER },
            hairLength: { type: Type.STRING, enum: ["short", "medium", "long"] },
            hairTexture: { type: Type.STRING, enum: ["straight", "curly"] }
          },
          required: ["skinTone", "skinAge", "eyeSize", "eyeTilt", "noseBridge", "noseWidth", "faceWidth", "cheekboneHeight", "jawShape", "lipFullness", "hairLength", "hairTexture"]
        }
      }
    });

    const result = JSON.parse(response.text);
