                   <div className="space-y-4">
                     <div className="space-y-2">
                        <span className="text-[9px] font-bold text-zinc-600 uppercase tracking-widest">Eyeliner</span>
                        <StyleSelector 
                          options={EYELINER_STYLES}
                          selectedId={state.makeup.eyelinerStyle}
                          onSelect={(id) => handleMakeupChange('eyelinerStyle', id)}
                        />
                      </div>

                      <div className="space-y-2">
                        <span className="text-[9px] font-bold text-zinc-600 uppercase tracking-widest">Lashes</span>
                        <StyleSelector 
                          options={EYELASH_STYLES}
                          selectedId={state.makeup.eyelashStyle}
                          onSelect={(id) => handleMakeupChange('eyelashStyle', id)}
                        />
                      </div>

                      <ColorSection label="Eyeshadow" id="eyeshadowColor" presets={MAKEUP_PRESETS.eyeshadow} colorValue={state.makeup.eyeshadowColor} disabled={false} onColorChange={handleMakeupChange} />
                   </div>
                </SubSection>

                <SubSection title="Cheek & Shading" defaultOpen={false}>
                  <div className="space-y-4">
                    <div className="space-y-2">
                      <span className="text-[9px] font-bold text-zinc-600 uppercase tracking-widest">Blush Style</span>
                      <StyleSelector 
                        options={BLUSH_STYLES}
                        selectedId={state.makeup.blushStyle}
                        onSelect={(id) => handleMakeupChange('blushStyle', id)}
                      />
                    </div>

                    <ColorSection label="Blush Color" id="blushColor" presets={MAKEUP_PRESETS.blush} colorValue={state.makeup.blushColor} disabled={false} onColorChange={handleMakeupChange} />

                    <div className="space-y-2">
                      <div className="flex justify-between text-[10px] font-bold">
                        <span className="text-zinc-500">Blush Intensity</span>
                        <span className="text-rose-400">{state.makeup.blushIntensity}</span>
                      </div>
                      <input type="range" min="0" max="100" value={state.makeup.blushIntensity} onChange={(e) => handleMakeupChange('blushIntensity', parseInt(e.target.value))} className="w-full accent-rose-500 h-1 bg-zinc-900 rounded-full appearance-none cursor-pointer" />
                    </div>

                    <div className="space-y-2">
                      <div className="flex justify-between text-[10px] font-bold">
                        <span className="text-zinc-500">Contour Shading</span>
                        <span className="text-indigo-400">{state.makeup.contourIntensity}</span>
                      </div>
                      <input type="range" min="0" max="100" value={state.makeup.contourIntensity} onChange={(e) => handleMakeupChange('contourIntensity', parseInt(e.target.value))} className="w-full accent-indigo-500 h-1 bg-zinc-900 rounded-full appearance-none cursor-pointer" />
                    </div>
                  </div>
                </SubSection>

                <SubSection title="Lip & Finish" defaultOpen={false}>
                  <div className="space-y-4">
                    <div className="space-y-2">
                      <span className="text-[9px] font-bold text-zinc-600 uppercase tracking-widest">Lip Finish</span>
                      <StyleSelector 
                        options={LIP_STYLES}
                        selectedId={state.makeup.lipStyle}
                        onSelect={(id) => handleMakeupChange('lipStyle', id)}
                      />
                    </div>
                    <ColorSection label="Lip Color" id="lipColor" presets={MAKEUP_PRESETS.lipstick} colorValue={state.makeup.lipColor} disabled={false} onColorChange={handleMakeupChange} />
                  </div>
                </SubSection>

                <div className="space-y-3 pt-5 border-t border-zinc-900">
                  <div className="flex items-center gap-2 text-zinc-500">
                    <MessageSquareText className="w-3 h-3" />
                    <span className="text-[9px] font-bold uppercase tracking-widest">Artist Notes</span>
                  </div>
                  <textarea value={state.customPrompts.makeup} onChange={(e) => handleCustomPromptChange('makeup', e.target.value)} placeholder="Glitter, matte finish, or specific reference..." className="w-full h-20 bg-zinc-900 border border-zinc-800 rounded-xl p-3 text-[10px] text-zinc-300 outline-none focus:border-rose-400 transition-all resize-none" />
                </div>
                {renderRefUploader('makeup', 'Makeup')}
              </CategoryAccordion>
            )}
          </div>
        )}
      </div>

      <div className="p-4 bg-zinc-950 border-t border-zinc-900">
        <div className="flex items-center gap-2 text-rose-400 mb-1">
          <Zap className="w-3 h-3 fill-current" />
          <span className="text-[9px] font-bold uppercase tracking-widest">Context Engine v7.5</span>
        </div>
        <p className="text-[10px] text-zinc-600 leading-tight">Smart Preset Linking Enabled.</p>
      </div>
    </aside>
  );
};

export interface FacialFeatures {
  eyeSize: number;
  lipThickness: number;
  noseWidth: number;
  eyelidType: 'Monolid' | 'Double' | 'Hooded';
  jawlineSharpness: number;
  canthalTilt: number; // eyeTilt
  jawShape: number;
  cheekboneHeight: number;
  faceWidth: number;
  eyeDistance: number;
  noseBridge: number;
  mouthCorners: number;
  lipCupidBow: number;
}

export interface SkinFeatures {
  tone: string;
  texture: string[];
  skinAge: number;
  glowIntensity: number;
  blemishIntensity: number;
}

export interface HairFeatures {
  hairStyle: string;
  hairLength: 'pixie' | 'leaf' | 'bob' | 'medium' | 'long' | 'extra_long';
  hairTexture: 'straight' | 'c_curl' | 's_curl' | 'jelly' | 'hippie' | 'hershey' | 'hime';
  bangStyle: 'none' | 'see_through' | 'full_blunt' | 'side' | 'choppy' | 'onion';
  hairVolume: number;
  hairShine: number;
  hairColorTop: string;
  hairColorBottom: string;
  hairColorBoundary: number;
}

export interface MakeupFeatures {
  makeupStyle: string;
  eyebrowStyle: 'straight' | 'arched' | 'hard_angled' | 'bushy';
  // FIX: Added 'classic', 'siren', and 'bold' to eyelinerStyle to match constants.tsx and PRESET_DEFAULTS
  eyelinerStyle: 'none' | 'tightline' | 'classic' | 'puppy' | 'cat' | 'siren' | 'bold' | 'smoky';
  eyelashStyle: 'natural' | 'mascara' | 'idol' | 'volume' | 'under';
  eyeshadowColor: string;
  eyelinerIntensity: number;
  blushStyle: 'none' | 'apples' | 'side' | 'drunken' | 'sunburn';
  blushColor: string;
  blushIntensity: number;
  contourIntensity: number;
  lipStyle: 'matte_blur' | 'glossy_tanghulu' | 'gradient' | 'overlip' | 'mlbb';
  lipColor: string;
  lipstickGloss: number;
}

export interface BeautyState {
  baseImage: string | null;
  referenceImages: {
    face: string | null;
    skin: string | null;
    hair: string | null;
    makeup: string | null;
  };
  features: FacialFeatures;
  skin: SkinFeatures;
  hair: HairFeatures;
  makeup: MakeupFeatures;
  customPrompts: {
    face: string;
    skin: string;
    hair: string;
    makeup: string;
  };
  editModes: {
    face: boolean;
    skin: boolean;
    hair: boolean;
    makeup: boolean;
  };
  aspectRatio: "1:1" | "3:4" | "4:3" | "9:16" | "16:9";
  // baseline stores the values detected by AI analysis to enable diff-based prompting
  baseline?: {
    features: Partial<FacialFeatures>;
    skin: Partial<SkinFeatures>;
    hair?: {
      hairLength: HairFeatures['hairLength'];
      hairTexture: HairFeatures['hairTexture'];
    };
  };
}

export enum TabType {
  FEATURES = 'FEATURES',
  SKIN = 'SKIN',
  HAIR = 'HAIR',
  MAKEUP = 'MAKEUP'
}

/**
 * Augmenting the global Window interface to include aistudio.
 */
declare global {
  interface AIStudio {
    hasSelectedApiKey: () => Promise<boolean>;
    openSelectKey: () => Promise<void>;
  }

  interface Window {
    aistudio?: AIStudio;
  }
}

