      ${modifications.some(m => m.includes("BONE") || m.includes("RECONSTRUCTION")) ? "OVERRIDE: Break original silhouette for bone/structure changes." : ""}
    `;
  }

  let makeupInstruction = "";
  if (isTargetedEdit && !editModes.makeup) {
    makeupInstruction = "PIXEL-LOCK MAKEUP: Do not add eyeliner, mascara, blush, or lipstick. Preserve original makeup state.";
  } else {
    const parts = [
      `Base Style: ${makeup.makeupStyle}`,
      `Eyeshadow: ${makeup.eyeshadowColor}`,
      `Blush: ${makeup.blushColor} (Intensity: ${makeup.blushIntensity}%)`,
      `Lips: ${makeup.lipColor} (${makeup.lipStyle})`
    ];

    if (makeup.eyelinerStyle !== 'none') {
      parts.push(`Eyeliner: ${STYLE_DESCRIPTIONS[makeup.eyelinerStyle] || makeup.eyelinerStyle}`);
    }
    if (makeup.eyelashStyle !== 'natural') {
      parts.push(`Eyelashes: ${STYLE_DESCRIPTIONS[makeup.eyelashStyle] || makeup.eyelashStyle}`);
    }

    makeupInstruction = `APPLICATION: ${parts.join(". ")}.`;
  }

  let skinInstruction = (isTargetedEdit && !editModes.skin) 
    ? "PIXEL-LOCK SKIN: Do not change the original skin tone, texture, or marks at all."
    : `RETEXTURE SKIN: Apply ${SKIN_TONES.find(t => t.id === skin.tone)?.prompt}. Texture: ${skin.texture.map(t => SKIN_TEXTURES.find(st => st.id === t)?.prompt).join(", ")}. Glow=${skin.glowIntensity}%, Age=${skin.skinAge}%, Imperfections=${skin.blemishIntensity}%.`;

  let hairInstruction = (isTargetedEdit && !editModes.hair)
    ? "PIXEL-LOCK HAIR: Preserve the original hairstyle, volume, and color perfectly."
    : `RECONSTRUCT HAIR: Style as ${hair.hairLength}, ${hair.hairTexture}. Volume=${hair.hairVolume}%, Shine/Gloss=${hair.hairShine}%. Gradient transition: Start with ${hair.hairColorTop} at roots, switching to ${hair.hairColorBottom} at exactly the ${hair.hairColorBoundary}% point from the top. ${getSliderAdjective(hair.hairShine, 'hairShine')}.`;

  return `Act as a world-class High-End Digital Plastic Surgeon and Editorial Retoucher.

    CORE MANDATE: 
    - If a specific mode is set to PIXEL-LOCK, you MUST NOT change that area.
    - PRESERVE GLOBAL TONE: Do not change the original image's lighting, white balance, or color grading unless explicitly asked.

    TRANSFORMATION DIRECTIVES:
    - FACE SHAPE & EYES: ${faceInstruction}
    - DERMATOLOGY: ${skinInstruction}
    - HAIR ARTISTRY: ${hairInstruction}
    - MAKEUP ARTISTRY: ${makeupInstruction}

    TECHNICAL SPECS:
    - Quality: 2K Ultra HD, Cinema grade lighting.
    - Consistency: STRICTLY Maintain the exact lighting and background of the INPUT BASE IMAGE. Do not apply "beauty filters" that wash out the image.`;
};

export const generateBeautyImage = async (state: BeautyState): Promise<string | null> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = generateBeautyPrompt(state);
  const parts: any[] = [{ text: prompt }];

  if (state.baseImage) {
    const baseData = state.baseImage.split(',')[1];
    const mimeType = state.baseImage.split(';')[0].split(':')[1];
    parts.push({ text: "INPUT BASE IMAGE" });
    parts.push({ inlineData: { data: baseData, mimeType } });
  }

  if (state.editModes.hair && state.referenceImages.hair) {
    const data = state.referenceImages.hair.split(',')[1];
    const mimeType = state.referenceImages.hair.split(';')[0].split(':')[1];
    parts.push({ text: "STYLE REFERENCE (HAIR)" });
    parts.push({ inlineData: { data, mimeType } });
  }

  if (state.editModes.makeup && state.referenceImages.makeup) {
    const data = state.referenceImages.makeup.split(',')[1];
    const mimeType = state.referenceImages.makeup.split(';')[0].split(':')[1];
    parts.push({ text: "STYLE REFERENCE (MAKEUP)" });
    parts.push({ inlineData: { data, mimeType } });
  }

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-image-preview',
      contents: { parts },
      config: {
        imageConfig: {
          aspectRatio: state.aspectRatio,
          imageSize: "2K"
        }
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
      }
    }
    return null;
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

