const StyleSelector = ({
  options,
  selectedId,
  onSelect,
  cols = 2
}: {
  options: { id: string, label: string }[],
  selectedId: string,
  onSelect: (id: string) => void,
  cols?: number
}) => {
  return (
    <div className={`grid grid-cols-${cols} gap-1.5`}>
      {options.map(opt => (
        <button
          key={opt.id}
          onClick={() => onSelect(opt.id)}
          className={`
            relative p-2 rounded-xl text-left transition-all group overflow-hidden border
            ${selectedId === opt.id 
              ? 'bg-zinc-800 border-indigo-500 shadow-md shadow-indigo-500/10' 
              : 'bg-zinc-900/40 border-zinc-800/50 hover:bg-zinc-800 hover:border-zinc-700'
            }
          `}
        >
          {selectedId === opt.id && (
            <div className="absolute top-0 right-0 w-2 h-2 bg-indigo-500 rounded-bl-lg" />
          )}
          <div className="flex flex-col gap-1">
            <span className={`text-[10px] font-bold leading-tight ${selectedId === opt.id ? 'text-white' : 'text-zinc-400 group-hover:text-zinc-300'}`}>
              {opt.label}
            </span>
          </div>
        </button>
      ))}
    </div>
  );
};

const SubSection = ({ 
