        <span className="text-[10px] font-bold text-zinc-400 uppercase tracking-widest flex items-center gap-2">
          {isOpen ? <ChevronDown className="w-3 h-3 text-zinc-600" /> : <ChevronRight className="w-3 h-3 text-zinc-600" />}
