const CategoryAccordion = ({ 
  title, 
  icon: Icon, 
  children, 
  defaultOpen = true,
  onOpenHelp,
  onReset
}: { 
  title: string, 
  icon: any, 
  children?: React.ReactNode, 
  defaultOpen?: boolean,
  onOpenHelp?: () => void,
  onReset?: () => void
}) => {
  const [isOpen, setIsOpen] = useState(defaultOpen);

  return (
    <div className="border-b border-zinc-900 last:border-0 bg-zinc-950/30">
