    switch (type) {
      case 'faceWidth': return "WIDENED BONE STRUCTURE; physically expand the zygomatic arches and temporal bones for a broader face";
      case 'jawlineSharpness': return "RAZOR-SHARP DEFINITION; eliminate all subcutaneous fat around the jaw, creating a distinct shadow line separating face and neck";
      case 'jawShape': return "STRONG L-SHAPED JAW; create a distinct, angular mandibular angle (aristocratic jawline)";
      case 'eyeSize': return "EXTREME enlargement; create a wide-eyed doll-like appearance with significantly larger irises";
      case 'lipThickness': return "MAXIMUM volume; perform massive vermilion border expansion for an extreme filler-injected look";
      case 'noseWidth': return "pronounced wide nasal base; broaden the nostrils for a strong, wide nose profile";
      case 'canthalTilt': return "HYPER-FELINE LIFT; physically pull the outer corners of the eyes drastically higher than the inner corners";
      case 'cheekboneHeight': return "HIGH-FASHION SKELETAL PROJECTION; create dramatic, protruding zygomatic arches with deep hollows underneath";
      case 'eyeDistance': return "WIDE-SET ALIEN LOOK; significantly increase the physical distance between the eyes across the nose bridge";
      case 'noseBridge': return "TALL ARCHITECTURE; raise the nasal bridge to a prominent, high-profile Grecian or Roman height";
      case 'mouthCorners': return "JOKER-LIKE UPTURN; create a permanent, deep upturn at the commissures for a smiling expression";
      case 'lipCupidBow': return "SURGICAL PRECISION; carve a very deep, sharp M-shaped cupid's bow with high peaks";
      case 'skinAge': return "ELDERLY CHARACTER; add realistic deep wrinkles, age spots, and sagging skin texture";
      case 'glowIntensity': return "OIL-SLICK SHINE; create a hyper-reflective, wet-look skin finish with blinding highlights";
      case 'blemishIntensity': return "RAW REALISM; add heavy freckles, visible pores, moles, and natural skin imperfections";
      case 'hairVolume': return "GRAVITY-DEFYING VOLUME; create massive root lift and a hyper-voluminous hair silhouette";
      case 'hairShine': return "HYPER-SILKY; provide a reflective, salon-quality mirror shine with zero frizz";
      case 'contourIntensity': return "EXTREME DRAG CONTOUR; apply very dark, sharp shadows to redefine the facial skeleton";
    }
  }
  if (value <= 15) { // Low Value Prompts
    switch (type) {
      case 'faceWidth': return "ULTRA-NARROW SKULL; physically compress the zygomatic width for a delicate, slender oval face shape";
      case 'jawlineSharpness': return "SOFT-FOCUS JAW; round out the mandibular line with soft tissue, removing any sharp definition";
      case 'jawShape': return "ROUND BABY-FACE; soften the jaw angle completely, adding volume to the lower cheeks for a chubby, youthful look";
      case 'eyeSize': return "MINIMALIST; significantly reduce eye size for a narrow, squinted, or hooded look";
      case 'lipThickness': return "PAPER-THIN; drastically reduce lip volume until the lips are nearly a straight line";
      case 'noseWidth': return "PINCHED RHINOPLASTY; extremely narrow the nasal ala and nostrils to a needle-thin point";
      case 'canthalTilt': return "DEEP PUPPY-EYE DROOP; physically lower the outer corners of the eyes below the inner corners";
      case 'cheekboneHeight': return "FLAT MIDFACE; completely suppress the cheekbones for a smooth, flat-cheeked appearance";
      case 'eyeDistance': return "CLOSE-SET; minimize the space between the eyes until they are nearly touching the bridge";
      case 'noseBridge': return "FLAT PROFILE; remove the nasal bridge height completely for a button-nose or flat aesthetic";
      case 'mouthCorners': return "MELANCHOLIC DROOP; pull the corners of the mouth down into a deep, sad pout";
      case 'lipCupidBow': return "SMOOTH ARCH; remove the cupid's bow peaks for a rounded, flat upper lip line";
      case 'skinAge': return "FETAL SMOOTHNESS; remove every single pore and line for an impossibly smooth, blurred finish";
      case 'glowIntensity': return "ULTRA-MATTE; remove all light reflection for a flat, velvet-like, chalky skin finish";
      case 'blemishIntensity': return "PORCELAIN DOLL; remove all skin texture, marks, and pores for a perfect, synthetic look";
      case 'hairVolume': return "FLAT-IRONED; collapse all volume for a sleek, thin hair look that hugs the skull";
      case 'hairShine': return "DRY & MATTE; create a raw, unstyled, matte hair texture with no highlights";
      case 'contourIntensity': return "FLAT LIGHTING; remove all shadows from the face for a flat, overexposed appearance";
    }
  }

  return `modified ${type}`;
};

const getDiffFeaturePrompt = (current: number, baseline: number | undefined, type: string): string => {
  const isStructural = ['jawShape', 'faceWidth', 'cheekboneHeight', 'jawlineSharpness', 'noseBridge', 'noseWidth', 'eyeDistance', 'canthalTilt'].includes(type);
  if (baseline === undefined) return `PIXEL-LOCK: Strictly preserve original ${type} structure.`;
  const diff = current - baseline;
  if (Math.abs(diff) < 5) return `PIXEL-LOCK: Strictly preserve original ${type}.`;
  const direction = diff > 0 ? "increase/broaden/raise/lift/sharpen" : "decrease/narrow/lower/drop/soften";
  const adjective = getSliderAdjective(current, type);
  if (isStructural) return `BONE RECONSTRUCTION: Physically ${direction} the skeletal structure of ${type}. BREAK THE ORIGINAL SILHOUETTE. Use ${adjective}.`;
  return `MORPHING: ${direction} the ${type} to be ${adjective}.`;
};

export const analyzeImageAttributes = async (base64Image: string) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const [header, data] = base64Image.split(';base64,');
  const mimeType = header.split(':')[1];
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview', 
      contents: {
        parts: [
          { inlineData: { data, mimeType } },
          { text: "Analyze the facial features of the person in this image. Focus on bone structure (cheekbones, face width, nose width) and eye positioning (tilt, distance) to prevent distortion. Return ONLY a JSON object." }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            skinTone: { type: Type.NUMBER },
            skinAge: { type: Type.NUMBER },
            eyeSize: { type: Type.NUMBER },
            eyeTilt: { type: Type.NUMBER },
            noseBridge: { type: Type.NUMBER },
            noseWidth: { type: Type.NUMBER },       
            faceWidth: { type: Type.NUMBER },       
            cheekboneHeight: { type: Type.NUMBER }, 
            jawShape: { type: Type.NUMBER },
            lipFullness: { type: Type.NUMBER },
            hairLength: { type: Type.STRING, enum: ["short", "medium", "long"] },
            hairTexture: { type: Type.STRING, enum: ["straight", "curly"] }
          },
          required: ["skinTone", "skinAge", "eyeSize", "eyeTilt", "noseBridge", "noseWidth", "faceWidth", "cheekboneHeight", "jawShape", "lipFullness", "hairLength", "hairTexture"]
        }
      }
    });
    return JSON.parse(response.text);
  } catch (error) { console.error("Attribute Analysis Error:", error); throw error; }
};

export const generateBeautyPrompt = (state: BeautyState): string => {
  const { features, skin, hair, makeup, editModes, baseline, referenceImages } = state;
  const activeCategories = Object.entries(editModes).filter(([_, active]) => active).map(([name]) => name);
  const isTargetedEdit = activeCategories.length > 0;

  // 1. FACE INSTRUCTION
  let faceInstruction = "";
  if (isTargetedEdit && !editModes.face) {
    faceInstruction = "STRICT PIXEL-LOCK: DO NOT change the face shape, eyes, nose, or mouth. Keep the original facial structure 100% identical.";
  } else if (referenceImages.face) {
    faceInstruction = "REFERENCE CLONING: Ignore all manual sliders. Analyze the 'FACIAL REF IMAGE' provided and replicate its bone structure, eye shape, nose shape, and jawline EXACTLY onto the base image. Make the subject look like the person in the reference image.";
  } else if (!isTargetedEdit || editModes.face) {
    const modifications: string[] = [];
    const preservations: string[] = [];
    const featureKeys = ['eyeSize', 'canthalTilt', 'noseBridge', 'lipThickness', 'noseWidth', 'jawlineSharpness', 'cheekboneHeight', 'faceWidth', 'eyeDistance', 'mouthCorners', 'lipCupidBow', 'jawShape'];
    featureKeys.forEach(key => {
      const current = (features as any)[key];
      const bl = (baseline?.features as any)?.[key];
      const instruction = getDiffFeaturePrompt(current, bl, key);
      if (instruction.includes("PIXEL-LOCK")) preservations.push(instruction);
      else modifications.push(instruction);
    });
    if (makeup.eyebrowStyle !== INITIAL_MAKEUP.eyebrowStyle) { modifications.push(`EYEBROWS: Change to ${STYLE_DESCRIPTIONS[makeup.eyebrowStyle] || makeup.eyebrowStyle}.`); }
    faceInstruction = `SURGICAL TARGETS: ${modifications.length > 0 ? modifications.join(" | ") : "None"}. PIXEL ANCHORS: ${preservations.join(" | ")}. ${modifications.some(m => m.includes("BONE") || m.includes("RECONSTRUCTION")) ? "OVERRIDE: Break original silhouette for bone/structure changes." : ""}`;
  }

  // 2. MAKEUP INSTRUCTION
  let makeupInstruction = "";
  if (isTargetedEdit && !editModes.makeup) {
    makeupInstruction = "PIXEL-LOCK MAKEUP: Do not add eyeliner, mascara, blush, or lipstick. Preserve original makeup state.";
  } else if (referenceImages.makeup) {
    makeupInstruction = "REFERENCE CLONING: Ignore manual makeup settings. Transfer the EXACT makeup look (eyeliner style, eyeshadow color, lipstick texture, blush placement) from the 'MAKEUP REF IMAGE' to the subject.";
  } else {
    const parts = [`Base Style: ${makeup.makeupStyle}`, `Eyebrows Color: ${makeup.eyebrowColor}`, `Eyeshadow: ${makeup.eyeshadowColor}`, `Blush: ${makeup.blushColor} (Intensity: ${makeup.blushIntensity}%)`, `Lips: ${makeup.lipColor} (${makeup.lipStyle})`];
    if (makeup.eyelinerStyle !== 'none') parts.push(`Eyeliner: ${STYLE_DESCRIPTIONS[makeup.eyelinerStyle] || makeup.eyelinerStyle}`);
    if (makeup.eyelashStyle !== 'natural') parts.push(`Eyelashes: ${STYLE_DESCRIPTIONS[makeup.eyelashStyle] || makeup.eyelashStyle}`);
    makeupInstruction = `APPLICATION: ${parts.join(". ")}.`;
  }

  // 3. SKIN INSTRUCTION
  let skinInstruction = "";
  if (isTargetedEdit && !editModes.skin) {
    skinInstruction = "PIXEL-LOCK SKIN: Do not change the original skin tone, texture, or marks at all.";
  } else if (referenceImages.skin) {
    skinInstruction = "REFERENCE CLONING: Ignore manual skin settings. Analyze the 'SKIN REF IMAGE' and transfer its exact skin texture, pore visibility, glow level, and complexion tone to the subject.";
  } else {
    skinInstruction = `RETEXTURE SKIN: Apply ${SKIN_TONES.find(t => t.id === skin.tone)?.prompt}. Texture: ${skin.texture.map(t => SKIN_TEXTURES.find(st => st.id === t)?.prompt).join(", ")}. Glow=${skin.glowIntensity}%, Age=${skin.skinAge}%, Imperfections=${skin.blemishIntensity}%.`;
  }

  // 4. HAIR INSTRUCTION
  let hairInstruction = "";
  if (isTargetedEdit && !editModes.hair) {
    hairInstruction = "PIXEL-LOCK HAIR: Preserve the original hairstyle, volume, and color perfectly.";
  } else if (referenceImages.hair) {
    hairInstruction = "REFERENCE CLONING: Ignore manual hair settings. Completely replace the subject's hair to match the 'HAIR REF IMAGE' in terms of cut, length, texture, volume, and color.";
  } else {
    hairInstruction = `RECONSTRUCT HAIR: Style as ${hair.hairLength}, ${hair.hairTexture}. Volume=${hair.hairVolume}%, Shine/Gloss=${hair.hairShine}%. Gradient transition: Start with ${hair.hairColorTop} at roots, switching to ${hair.hairColorBottom} at exactly the ${hair.hairColorBoundary}% point from the top. ${getSliderAdjective(hair.hairShine, 'hairShine')}.`;
  }

  return `Act as a world-class High-End Digital Plastic Surgeon and Editorial Retoucher.

    CORE MANDATE: 
    - **REFERENCE PRIORITY**: If a reference image is provided for a category, YOU MUST COPY IT EXACTLY and IGNORE any conflicting text instructions for that category.
    - If a specific mode is set to PIXEL-LOCK, you MUST NOT change that area.
    - PRESERVE GLOBAL TONE: Do not change the original image's lighting, white balance, or color grading unless explicitly asked.

    TRANSFORMATION DIRECTIVES:
    - FACE SHAPE & EYES: ${faceInstruction}
    - DERMATOLOGY: ${skinInstruction}
    - HAIR ARTISTRY: ${hairInstruction}
    - MAKEUP ARTISTRY: ${makeupInstruction}

    TECHNICAL SPECS:
    - Quality: 2K Ultra HD, Cinema grade lighting.
    - Consistency: STRICTLY Maintain the exact lighting and background of the INPUT BASE IMAGE. Do not apply "beauty filters" that wash out the image.`;
};

export const generateBeautyImage = async (state: BeautyState): Promise<string | null> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = generateBeautyPrompt(state);
  const parts: any[] = [{ text: prompt }];
  if (state.baseImage) { const baseData = state.baseImage.split(',')[1]; const mimeType = state.baseImage.split(';')[0].split(':')[1]; parts.push({ text: "INPUT BASE IMAGE" }); parts.push({ inlineData: { data: baseData, mimeType } }); }
  if (state.editModes.hair && state.referenceImages.hair) { const data = state.referenceImages.hair.split(',')[1]; const mimeType = state.referenceImages.hair.split(';')[0].split(':')[1]; parts.push({ text: "HAIR REF IMAGE" }); parts.push({ inlineData: { data, mimeType } }); }
  if (state.editModes.makeup && state.referenceImages.makeup) { const data = state.referenceImages.makeup.split(',')[1]; const mimeType = state.referenceImages.makeup.split(';')[0].split(':')[1]; parts.push({ text: "MAKEUP REF IMAGE" }); parts.push({ inlineData: { data, mimeType } }); }
  if (state.editModes.skin && state.referenceImages.skin) { const data = state.referenceImages.skin.split(',')[1]; const mimeType = state.referenceImages.skin.split(';')[0].split(':')[1]; parts.push({ text: "SKIN REF IMAGE" }); parts.push({ inlineData: { data, mimeType } }); }
  if (state.editModes.face && state.referenceImages.face) { const data = state.referenceImages.face.split(',')[1]; const mimeType = state.referenceImages.face.split(';')[0].split(':')[1]; parts.push({ text: "FACIAL REF IMAGE" }); parts.push({ inlineData: { data, mimeType } }); }

  try {
    const response = await ai.models.generateContent({ model: 'gemini-3-pro-image-preview', contents: { parts }, config: { imageConfig: { aspectRatio: state.aspectRatio, imageSize: "2K" } } });
    for (const part of response.candidates?.[0]?.content?.parts || []) { if (part.inlineData) { return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`; } }
    return null;
  } catch (error) { console.error("Gemini API Error:", error); throw error; }
};

