export const StudioSidebar: React.FC<SidebarProps> = ({ state, updateState, onRefUpload, onResetCategory }) => {
  const [activeHelpId, setActiveHelpId] = useState<keyof typeof HELP_CONTENT | null>(null);
  const [isMultiMode, setIsMultiMode] = useState(false);

  const handlePresetChange = (presetId: string) => {
    const defaults = PRESET_DEFAULTS[presetId];
    updateState({ makeup: { ...state.makeup, makeupStyle: presetId, ...(defaults || {}) } });
  };

  const handleFeatureChange = useCallback((key: string, value: any) => { updateState({ features: { ...state.features, [key]: value } }); }, [state.features, updateState]);
  const handleMakeupChange = useCallback((id: string, value: any) => { updateState({ makeup: { ...state.makeup, [id]: value } }); }, [state.makeup, updateState]);
