import React, { useMemo } from 'react';
import { Loader2, Maximize2, Download, Wand2, FlaskConical } from 'lucide-react';
import { BeautyState } from '../types';

interface PreviewProps {
  image: string | null;
  baseImage: string | null;
  loading: boolean;
  onDownload?: () => void;
  state: BeautyState; // [NEW] 상태값 접근을 위해 추가
}

export const PreviewCanvas: React.FC<PreviewProps> = ({ image, baseImage, loading, onDownload, state }) => {

  // [SIMULATION ENGINE] CSS 기반 실시간 시뮬레이션 스타일 계산
  const simulationStyle = useMemo(() => {
    // 결과 이미지가 있거나 로딩 중이면 시뮬레이션 중단
    if (image || loading || !baseImage) return {};

    const { features, skin } = state;

    // 1. Face Width Simulation (CSS Transform)
    // 50을 기준으로 0.95(홀쭉) ~ 1.05(통통) 범위로 스케일 조절
    const scaleX = 0.95 + (features.faceWidth / 100) * 0.1;

    // 2. Skin Tone & Age Simulation (CSS Filters)
    // Skin Age: 낮을수록 밝고 블러 처리 (동안 효과), 높을수록 선명하고 어두움
    const blur = features.jawlineSharpness > 80 ? '0px' : `${(100 - state.skin.skinAge) * 0.01}px`;
    const brightness = 0.9 + (100 - state.skin.skinAge) * 0.002; // 0.9 ~ 1.1

    // Glow: 높을수록 대비(Contrast)와 채도(Saturate) 증가
    const contrast = 0.9 + (skin.glowIntensity / 100) * 0.2;
    const saturate = 0.8 + (skin.glowIntensity / 100) * 0.4;

    return {
      transform: `scaleX(${scaleX})`,
      filter: `brightness(${brightness}) contrast(${contrast}) saturate(${saturate}) blur(${blur})`,
      transition: 'all 0.3s cubic-bezier(0.4, 0, 0.2, 1)' // 부드러운 전환 효과
    };
  }, [state, image, loading, baseImage]);

  return (
    <div className="w-full h-full relative group overflow-hidden bg-black/50 flex items-center justify-center">
      {/* Loading Overlay */}
      {loading && (
        <div className="absolute inset-0 z-50 bg-zinc-950/80 backdrop-blur-sm flex flex-col items-center justify-center gap-6">
          <div className="relative">
            <Loader2 className="w-12 h-12 text-indigo-500 animate-spin" />
            <div className="absolute inset-0 blur-xl bg-indigo-500/20 animate-pulse" />
          </div>
          <div className="text-center space-y-2">
            <h3 className="text-lg font-semibold text-white">Synthesizing Aesthetics...</h3>
            <p className="text-zinc-500 text-sm max-w-[240px] mx-auto animate-pulse">
              Gemini AI is calculating facial symmetry and high-resolution skin textures.
            </p>
          </div>
        </div>
      )}

      {/* Main Image Display */}
      {image ? (
        // [CASE 1] 생성된 결과 이미지 (Simulation OFF)
        <>
          <img src={image} className="w-full h-full object-contain animate-in fade-in duration-500" alt="Generated Beauty" />
          <div className="absolute bottom-4 right-4 flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
            {onDownload && (
              <button 
                onClick={(e) => { e.stopPropagation(); onDownload(); }}
                className="p-3 bg-indigo-600 hover:bg-indigo-500 rounded-xl text-white shadow-xl flex items-center gap-2 text-xs font-bold transition-all active:scale-90"
              >
                <Download className="w-4 h-4" />
                Save 2K UHD
              </button>
            )}
            <button className="p-3 bg-black/50 backdrop-blur-md rounded-xl text-white hover:bg-black/70 transition-all">
              <Maximize2 className="w-4 h-4" />
            </button>
          </div>
        </>
      ) : baseImage ? (
        // [CASE 2] 베이스 이미지 + 실시간 시뮬레이션 (Simulation ON)
        <div className="relative w-full h-full flex items-center justify-center overflow-hidden">
          <img 
            src={baseImage} 
            className="max-w-full max-h-full object-contain will-change-transform" 
            style={simulationStyle}
            alt="Base Simulation" 
          />

          {/* Simulation Badge */}
          <div className="absolute top-4 right-4 bg-zinc-900/80 backdrop-blur-md border border-indigo-500/30 px-3 py-1.5 rounded-full flex items-center gap-2 shadow-lg">
            <FlaskConical className="w-3 h-3 text-indigo-400 animate-pulse" />
            <span className="text-[10px] font-bold text-indigo-200 uppercase tracking-widest">
              Live Preview
            </span>
          </div>

          <div className="absolute bottom-6 bg-black/40 backdrop-blur-sm px-4 py-2 rounded-full border border-white/10">
            <p className="text-[10px] text-zinc-300 font-medium">
              💡 Drag sliders to see real-time simulation
            </p>
          </div>
        </div>
      ) : (
        // [CASE 3] Empty State
        <div className="absolute inset-0 flex flex-col items-center justify-center p-8 text-center gap-4">
          <div className="w-20 h-20 rounded-3xl bg-zinc-900 border border-zinc-800 flex items-center justify-center">
            <span className="text-3xl font-bold text-zinc-700">?</span>
          </div>
          <div className="space-y-1">
            <h3 className="text-zinc-300 font-medium">No results yet</h3>
            <p className="text-zinc-500 text-sm">Upload a base image and start the synthesis to see the results.</p>
          </div>
        </div>
      )}
    </div>
  );
};

