      const faceAreaRatio = (data.faceBoundingBox.xmax - data.faceBoundingBox.xmin) * (data.faceBoundingBox.ymax - data.faceBoundingBox.ymin);
      if (faceAreaRatio < 0.25) {
        setIsCropping(true);
        try {
          finalBaseImage = await performSmartCrop(originalImage, data.faceBoundingBox);
