1. src/App.tsx (좌표 정규화 및 민감도 상향)

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { StudioSidebar } from './components/StudioSidebar';
import { PreviewCanvas } from './components/PreviewCanvas';
import { ApiKeyModal } from './components/ApiKeyModal';
import { generateBeautyImage, generateBeautyPrompt, analyzeImageAttributes } from './services/geminiService';
import { BeautyState } from './types';
import { INITIAL_FEATURES, INITIAL_HAIR, INITIAL_MAKEUP } from './constants';
import { Sparkles, Upload, Trash2, Zap, Eye, EyeOff, Download, RefreshCcw, Search, Scissors } from 'lucide-react';

const App: React.FC = () => {
  const [state, setState] = useState<BeautyState>({
    baseImage: null,
    referenceImages: { face: null, skin: null, hair: null, makeup: null },
    features: INITIAL_FEATURES,
    skin: { tone: 'natural', texture: ['Smooth'], skinAge: 20, glowIntensity: 50, blemishIntensity: 10 },
    hair: INITIAL_HAIR,
    makeup: INITIAL_MAKEUP,
    customPrompts: { face: '', skin: '', hair: '', makeup: '' },
    editModes: { face: false, skin: false, hair: false, makeup: false },
    aspectRatio: '1:1',
    baseline: undefined
  });

  const [isGenerating, setIsGenerating] = useState(false);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [isCropping, setIsCropping] = useState(false);
  const [generatedImage, setGeneratedImage] = useState<string | null>(null);
  const [needsKey, setNeedsKey] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isComparing, setIsComparing] = useState(false);

  useEffect(() => {
    const checkKey = async () => {
      if (window.aistudio) {
        const hasKey = await window.aistudio.hasSelectedApiKey();
        setNeedsKey(!hasKey);
      }
    };
    checkKey();
  }, []);

  // [SMART CROP] 얼굴 좌표를 기반으로 최적의 인물 구도로 자르기
  const performSmartCrop = async (imageSrc: string, bbox: { ymin: number, xmin: number, ymax: number, xmax: number }): Promise<string> => {
    return new Promise((resolve) => {
      const img = new Image();
      img.onload = () => {
        const canvas = document.createElement('canvas');
        const ctx = canvas.getContext('2d');
        if (!ctx) return resolve(imageSrc);

        const { width, height } = img;

        // [FIX] 좌표 정규화 (Safety Check)
        // AI가 0~1000 단위로 줄 경우를 대비해 1보다 크면 1000으로 나눔
        let { ymin, xmin, ymax, xmax } = bbox;
        if (xmax > 1 || ymax > 1) {
          ymin /= 1000; xmin /= 1000; ymax /= 1000; xmax /= 1000;
        }

        const faceW = (xmax - xmin) * width;
        const faceH = (ymax - ymin) * height;
        const faceCX = (xmin + xmax) * width / 2;
        const faceCY = (ymin + ymax) * height / 2;

        // 크롭 영역 계산 (얼굴 크기의 2.2배 정도 여유)
        let cropW = faceW * 2.2; 

        // 너무 작게 잘리는 것 방지 (최소 이미지 너비의 40%)
        if (cropW < width * 0.4) cropW = width * 0.4;

        let cropH = cropW * 1.3; // 4:5 ~ 3:4 비율 (Portrait)

        // 중심점 조정: 얼굴이 사진의 수직 중앙보다 약간 위에 오도록 (황금비율)
        let startX = faceCX - cropW / 2;
        let startY = faceCY - faceH * 0.7; // 얼굴 중심에서 조금 더 위(이마/정수리)를 포함

        // 경계 벗어남 방지 (Clamping)
        if (startX < 0) startX = 0;
        if (startY < 0) startY = 0;
        if (startX + cropW > width) {
           // 오른쪽이 잘리면 왼쪽으로 이동
           startX = width - cropW;
           if (startX < 0) { startX = 0; cropW = width; } // 그래도 크면 전체 폭 사용
        }
        if (startY + cropH > height) {
           // 아래가 잘리면 위로 이동하지 않고 높이를 줄임 (하반신보다는 얼굴 위주)
           cropH = height - startY; 
        }

        canvas.width = cropW;
        canvas.height = cropH;

        // 배경을 검은색으로 채우지 않고 이미지 그리기
        ctx.fillStyle = "#000000";
        ctx.fillRect(0, 0, cropW, cropH);
        ctx.drawImage(img, startX, startY, cropW, cropH, 0, 0, cropW, cropH);

        resolve(canvas.toDataURL('image/jpeg', 0.95));
      };
      img.onerror = () => resolve(imageSrc);
      img.src = imageSrc;
    });
  };

  const applyAnalysis = async (data: any, originalImage: string) => {
    let finalBaseImage = originalImage;

    // [FIX] 자동 크롭 트리거 로직 개선
    // 1. 좌표 정규화 체크
    let { xmin, xmax, ymin, ymax } = data.faceBoundingBox;
    if (xmax > 1 || ymax > 1) {
      xmin /= 1000; xmax /= 1000; ymin /= 1000; ymax /= 1000;
    }

    // 2. 얼굴 면적 비율 계산
    const faceAreaRatio = (xmax - xmin) * (ymax - ymin);

    // [FIX] 민감도 상향: 얼굴이 전체의 40% 미만이면 무조건 크롭 (기존 25% -> 40%)
    // 전신/반신샷은 보통 얼굴 비율이 10~15% 내외임.
    console.log(`Face Ratio Detected: ${(faceAreaRatio * 100).toFixed(2)}%`);

    if (faceAreaRatio < 0.40) {
      setIsCropping(true);
      try {
        // 원본 좌표 데이터 그대로 전달 (함수 내부에서 다시 정규화 체크함)
        finalBaseImage = await performSmartCrop(originalImage, data.faceBoundingBox);
      } catch (e) {
        console.error("Auto Crop Failed:", e);
      } finally {
        setIsCropping(false);
      }
    }

    const skinToneId = data.skinTone < 20 ? 'porcelain' : data.skinTone < 40 ? 'fair' : data.skinTone < 60 ? 'natural' : data.skinTone < 80 ? 'tanned' : 'deep';
    const hairLen = data.hairLength === 'short' ? 'bob' : data.hairLength === 'medium' ? 'shoulder' : 'long';
    const hairTex = data.hairTexture === 'straight' ? 'straight' : 'waves';

    const analyzedFeatures = {
      ...INITIAL_FEATURES, 
      eyeSize: data.eyeSize, 
      canthalTilt: data.eyeTilt,
      noseBridge: data.noseBridge,
      jawShape: data.jawShape,
      lipThickness: data.lipFullness,
      noseWidth: data.noseWidth ?? 50,
      faceWidth: data.faceWidth ?? 50,
      cheekboneHeight: data.cheekboneHeight ?? 50,
    };

    const analyzedSkin = { ...state.skin, tone: skinToneId, skinAge: data.skinAge };
    const analyzedHair = { ...state.hair, hairLength: hairLen, hairTexture: hairTex };

    setState(prev => ({
      ...prev,
      baseImage: finalBaseImage, 
      features: analyzedFeatures,
      skin: analyzedSkin,
      hair: analyzedHair,
      baseline: { features: analyzedFeatures, skin: analyzedSkin, hair: analyzedHair }
    }));
  };

  const resetCategory = useCallback((category: 'face' | 'skin' | 'hair' | 'makeup') => {
    setState(prev => {
      const newState = { ...prev };
      const bl = prev.baseline;
      switch (category) {
        case 'face': newState.features = { ...INITIAL_FEATURES, ...(bl?.features || {}) }; newState.makeup = { ...prev.makeup, eyebrowStyle: INITIAL_MAKEUP.eyebrowStyle, eyelinerStyle: INITIAL_MAKEUP.eyelinerStyle, eyelashStyle: INITIAL_MAKEUP.eyelashStyle }; newState.customPrompts = { ...prev.customPrompts, face: '' }; break;
        case 'skin': newState.skin = { ...prev.skin, tone: bl?.skin?.tone || 'natural', skinAge: bl?.skin?.skinAge || 20, glowIntensity: 50, blemishIntensity: 10, texture: ['Smooth'] }; newState.customPrompts = { ...prev.customPrompts, skin: '' }; break;
        case 'hair': newState.hair = { ...INITIAL_HAIR, hairLength: bl?.hair?.hairLength || INITIAL_HAIR.hairLength, hairTexture: bl?.hair?.hairTexture || INITIAL_HAIR.hairTexture }; newState.customPrompts = { ...prev.customPrompts, hair: '' }; break;
        case 'makeup': newState.makeup = { ...INITIAL_MAKEUP, eyebrowStyle: prev.makeup.eyebrowStyle, eyelinerStyle: prev.makeup.eyelinerStyle, eyelashStyle: prev.makeup.eyelashStyle }; newState.customPrompts = { ...prev.customPrompts, makeup: '' }; break;
      }
      return newState;
    });
  }, []);

  const handleGenerate = async () => {
    try {
      setIsGenerating(true);
      setError(null);
      const result = await generateBeautyImage(state);
      if (result) { setGeneratedImage(result); } else { setError("Synthesis failed. Please check your settings and try again."); }
    } catch (err: any) {
      if (err.message?.includes("Requested entity was not found")) { setNeedsKey(true); }
      setError(err.message || "An error occurred during synthesis.");
    } finally { setIsGenerating(false); }
  };

  const handleDownload = () => {
    if (!generatedImage) return;
    const link = document.createElement('a');
    link.href = generatedImage;
    link.download = `BeautySynth_Pro_2K_${Date.now()}.png`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleUseAsBase = () => {
    if (!generatedImage) return;
    updateState({ baseImage: generatedImage, baseline: undefined });
    setGeneratedImage(null);
    setIsComparing(false);
  };

  const updateState = (updates: Partial<BeautyState>) => { setState(prev => ({ ...prev, ...updates })); };

  const calculateAspectRatio = (img: HTMLImageElement): "1:1" | "3:4" | "4:3" | "9:16" | "16:9" => {
    const ratio = img.width / img.height;
    const options: { label: "1:1" | "3:4" | "4:3" | "9:16" | "16:9", value: number }[] = [
      { label: "1:1", value: 1 }, { label: "3:4", value: 0.75 }, { label: "4:3", value: 1.33 }, { label: "9:16", value: 0.5625 }, { label: "16:9", value: 1.777 }
    ];
    return options.reduce((prev, curr) => Math.abs(curr.value - ratio) < Math.abs(prev.value - ratio) ? curr : prev).label;
  };

  const onFileUpload = (type: 'base' | 'face' | 'skin' | 'hair' | 'makeup') => (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = reader.result as string;
        if (type === 'base') {
          const img = new Image();
          img.onload = async () => {
            const ratio = calculateAspectRatio(img);
            updateState({ baseImage: base64String, aspectRatio: ratio, baseline: undefined });
            try {
              setIsAnalyzing(true);
              const analysis = await analyzeImageAttributes(base64String);
              await applyAnalysis(analysis, base64String);
            } catch (err) {
              console.error("AI Analysis failed:", err);
              setError("AI analysis failed. Please adjust features manually.");
            } finally {
              setIsAnalyzing(false);
            }
          };
          img.src = base64String;
        } else {
          updateState({ referenceImages: { ...state.referenceImages, [type]: base64String } });
        }
      };
      reader.readAsDataURL(file);
    }
  };

  const currentPrompt = useMemo(() => generateBeautyPrompt(state), [state]);

  if (needsKey) { return <ApiKeyModal onComplete={() => setNeedsKey(false)} />; }

  return (
    <div className="flex flex-col h-screen bg-black overflow-hidden text-zinc-100">
      <header className="h-16 border-b border-zinc-900 flex items-center justify-between px-6 bg-zinc-950/80 backdrop-blur-xl z-50">
        <div className="flex items-center gap-3"><div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center shadow-lg shadow-indigo-500/20"><Sparkles className="w-6 h-6 text-white" /></div><div><h1 className="text-lg font-bold tracking-tight">BeautySynth <span className="text-indigo-500">PRO</span></h1><p className="text-[10px] text-zinc-500 font-bold uppercase tracking-widest">Powered by Gemini 2.0 Flash</p></div></div>
        <div className="flex items-center gap-4"><button onClick={handleGenerate} disabled={isGenerating || !state.baseImage} className={`flex items-center gap-2 px-8 py-2.5 rounded-full font-bold transition-all ${isGenerating || !state.baseImage ? 'bg-zinc-900 text-zinc-600 cursor-not-allowed opacity-50' : 'bg-indigo-600 hover:bg-indigo-500 text-white active:scale-95 shadow-xl shadow-indigo-600/20'}`}>{isGenerating ? (<div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" />) : <Zap className="w-4 h-4 fill-current" />}{isGenerating ? 'Synthesizing (2K)...' : 'Generate Synthesis'}</button></div>
      </header>

      <main className="flex flex-1 overflow-hidden">
        <StudioSidebar state={state} updateState={updateState} onRefUpload={onFileUpload} onResetCategory={resetCategory} />

        <div className="flex-1 p-6 flex flex-col gap-6 overflow-hidden bg-zinc-950">
          {error && <div className="bg-red-500/10 border border-red-500/20 text-red-400 p-3 rounded-xl flex items-center justify-between text-sm shrink-0"><span>{error}</span><button onClick={() => setError(null)}>✕</button></div>}

          <div className="flex flex-col flex-1 min-h-0 gap-6">
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 flex-1 min-h-0">
              <div className="bg-zinc-900/50 border border-zinc-800/50 rounded-3xl overflow-hidden flex flex-col relative group shadow-inner">
                <div className="p-4 border-b border-zinc-800/50 flex justify-between items-center bg-zinc-900/30">
                  <h3 className="text-[10px] font-bold text-zinc-500 uppercase tracking-widest">Input: Base Image</h3>
                  <div className="flex items-center gap-2">
                    {isAnalyzing && <span className="text-[10px] font-bold text-indigo-400 animate-pulse flex items-center gap-1"><Search className="w-3 h-3" /> Analyzing...</span>}
                    {isCropping && <span className="text-[10px] font-bold text-emerald-400 animate-pulse flex items-center gap-1"><Scissors className="w-3 h-3" /> Auto-Cropping...</span>}
                    {state.baseImage && <button onClick={() => updateState({ baseImage: null, baseline: undefined })} className="text-zinc-600 hover:text-red-400"><Trash2 className="w-4 h-4" /></button>}
                  </div>
                </div>
                <div className="flex-1 flex items-center justify-center relative bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-zinc-900 to-black overflow-hidden">
                  {state.baseImage ? (
                    <>
                      <img src={state.baseImage} className={`max-w-full max-h-full object-contain transition-opacity duration-500 ${isAnalyzing ? 'opacity-40 grayscale' : 'opacity-100'}`} alt="Base" />
                      {(isAnalyzing || isCropping) && (
                        <div className="absolute inset-0 flex flex-col items-center justify-center pointer-events-none">
                           <div className="w-full h-1 bg-indigo-500/30 overflow-hidden absolute top-0"><div className="w-1/3 h-full bg-indigo-500 animate-[scan_2s_linear_infinite]" /></div>
                           <div className="bg-black/60 backdrop-blur-md px-4 py-2 rounded-full border border-indigo-500/30 shadow-2xl flex items-center gap-2">
                             <div className="w-3 h-3 border-2 border-indigo-500 border-t-transparent rounded-full animate-spin" />
                             <span className="text-xs font-bold text-indigo-400 uppercase tracking-widest">{isCropping ? 'Smart Cropping...' : 'Extracting Features'}</span>
                           </div>
                        </div>
                      )}
                    </>
                  ) : (
                    <label className="cursor-pointer flex flex-col items-center gap-4"><div className="w-20 h-20 rounded-full bg-zinc-800 flex items-center justify-center text-zinc-500 hover:text-indigo-400 transition-colors border border-zinc-700"><Upload className="w-8 h-8" /></div><span className="text-zinc-500 font-medium text-sm">Upload Base Image</span><input type="file" className="hidden" accept="image/*" onChange={onFileUpload('base')} /></label>
                  )}
                </div>
              </div>

              <div className="bg-zinc-900/50 border border-zinc-800/50 rounded-3xl overflow-hidden flex flex-col relative shadow-2xl">
                <div className="p-4 border-b border-zinc-800/50 flex justify-between items-center bg-zinc-900/30">
                  <h3 className="text-[10px] font-bold text-zinc-500 uppercase tracking-widest">Synthesis Result: 2K UHD</h3>
                  <div className="flex gap-2">
                    {generatedImage && (
                      <>
                        <button onClick={handleUseAsBase} className="text-[10px] font-bold uppercase tracking-widest text-indigo-400 flex items-center gap-2 px-3 py-1 rounded-full bg-indigo-500/10 border border-indigo-500/20 active:scale-95 transition-all hover:bg-indigo-500/20" title="Use result as base"><RefreshCcw className="w-3 h-3" /> Use as Base</button>
                        <button onClick={handleDownload} className="text-[10px] font-bold uppercase tracking-widest text-emerald-400 flex items-center gap-2 px-3 py-1 rounded-full bg-emerald-500/10 border border-emerald-500/20 active:scale-95 transition-all hover:bg-emerald-500/20"><Download className="w-3 h-3" /> Download</button>
                        <button onMouseDown={() => setIsComparing(true)} onMouseUp={() => setIsComparing(false)} onMouseLeave={() => setIsComparing(false)} className="text-[10px] font-bold uppercase tracking-widest text-zinc-400 flex items-center gap-2 px-3 py-1 rounded-full bg-zinc-500/10 border border-zinc-500/20 active:scale-95 select-none transition-all hover:bg-zinc-500/20">{isComparing ? <EyeOff className="w-3 h-3" /> : <Eye className="w-3 h-3" />} Compare</button>
                      </>
                    )}
                  </div>
                </div>
                <div className="flex-1 bg-black relative flex items-center justify-center group overflow-hidden">
                  <PreviewCanvas image={isComparing ? state.baseImage : generatedImage} baseImage={state.baseImage} loading={isGenerating} onDownload={handleDownload} state={state} />
                  {isComparing && <div className="absolute top-4 left-4 px-3 py-1 bg-black/80 text-[10px] font-bold text-white uppercase tracking-widest rounded-full border border-white/20">Original</div>}
                </div>
              </div>
            </div>

            <div className="bg-zinc-900/50 border border-zinc-800/50 rounded-3xl p-4 flex flex-col gap-2 shrink-0 h-28 shadow-inner overflow-hidden">
              <h3 className="text-[10px] font-bold text-zinc-500 uppercase tracking-widest flex items-center gap-2"><Zap className="w-3 h-3 text-indigo-500" /> Targeted Synthesis Prompt Preview</h3>
              <div className="flex-1 overflow-y-auto text-[11px] text-zinc-400 leading-relaxed font-mono bg-black/30 p-3 rounded-xl border border-zinc-800/50">{currentPrompt}</div>
            </div>
