};

export const generateBeautyImage = async (state: BeautyState): Promise<string | null> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = generateBeautyPrompt(state);
  const parts: any[] = [{ text: prompt }];
  if (state.baseImage) { parts.push({ text: "INPUT BASE IMAGE" }); parts.push({ inlineData: { data: state.baseImage.split(',')[1], mimeType: state.baseImage.split(';')[0].split(':')[1] } }); }
  if (state.editModes.hair && state.referenceImages.hair) { parts.push({ text: "HAIR REF IMAGE" }); parts.push({ inlineData: { data: state.referenceImages.hair.split(',')[1], mimeType: state.referenceImages.hair.split(';')[0].split(':')[1] } }); }
  if (state.editModes.makeup && state.referenceImages.makeup) { parts.push({ text: "MAKEUP REF IMAGE" }); parts.push({ inlineData: { data: state.referenceImages.makeup.split(',')[1], mimeType: state.referenceImages.makeup.split(';')[0].split(':')[1] } }); }
  if (state.editModes.skin && state.referenceImages.skin) { parts.push({ text: "SKIN REF IMAGE" }); parts.push({ inlineData: { data: state.referenceImages.skin.split(',')[1], mimeType: state.referenceImages.skin.split(';')[0].split(':')[1] } }); }
  if (state.editModes.face && state.referenceImages.face) { parts.push({ text: "FACIAL REF IMAGE" }); parts.push({ inlineData: { data: state.referenceImages.face.split(',')[1], mimeType: state.referenceImages.face.split(';')[0].split(':')[1] } }); }

  try {
    const response = await ai.models.generateContent({ model: 'gemini-3-pro-image-preview', contents: { parts }, config: { imageConfig: { aspectRatio: state.aspectRatio, imageSize: "2K" } } });
    for (const part of response.candidates?.[0]?.content?.parts || []) { if (part.inlineData) { return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`; } }
    return null;
  } catch (error) { console.error("Gemini API Error:", error); throw error; }
};

import React, { useState, useEffect, useMemo, useCallback } from 'react';
