      if (window.aistudio) {
        const hasKey = await window.aistudio.hasSelectedApiKey();
        setNeedsKey(!hasKey);
      }
    };
    checkKey();
  }, []);

  const performSmartCrop = async (imageSrc: string, bbox: { ymin: number, xmin: number, ymax: number, xmax: number }): Promise<string> => {
    return new Promise((resolve) => {
      const img = new Image();
      img.onload = () => {
        const canvas = document.createElement('canvas');
        const ctx = canvas.getContext('2d');
        if (!ctx) return resolve(imageSrc);

        const { width, height } = img;
        let { ymin, xmin, ymax, xmax } = bbox;
        if (xmax > 1 || ymax > 1) {
          ymin /= 1000; xmin /= 1000; ymax /= 1000; xmax /= 1000;
        }

        const faceW = (xmax - xmin) * width;
        const faceH = (ymax - ymin) * height;
        const faceCX = (xmin + xmax) * width / 2;
        const faceCY = (ymin + ymax) * height / 2;

        let cropW = faceW * 2.2; 
        if (cropW < width * 0.4) cropW = width * 0.4;
        let cropH = cropW * 1.3;

        let startX = faceCX - cropW / 2;
        let startY = faceCY - faceH * 0.7;

        if (startX < 0) startX = 0;
        if (startY < 0) startY = 0;
        if (startX + cropW > width) startX = width - cropW;
        if (startY + cropH > height) cropH = height - startY;

        canvas.width = cropW;
        canvas.height = cropH;
        ctx.fillStyle = "#000000";
        ctx.fillRect(0, 0, cropW, cropH);
        ctx.drawImage(img, startX, startY, cropW, cropH, 0, 0, cropW, cropH);
        resolve(canvas.toDataURL('image/jpeg', 0.95));
      };
      img.onerror = () => resolve(imageSrc);
      img.src = imageSrc;
    });
  };

  const applyAnalysis = async (data: any, originalImage: string) => {
    let finalBaseImage = originalImage;
    if (data.faceBoundingBox) {
      let { xmin, xmax, ymin, ymax } = data.faceBoundingBox;
      if (xmax > 1 || ymax > 1) { xmin /= 1000; xmax /= 1000; ymin /= 1000; ymax /= 1000; }
      const faceAreaRatio = (xmax - xmin) * (ymax - ymin);
      if (faceAreaRatio < 0.40) {
        setIsCropping(true);
        try { finalBaseImage = await performSmartCrop(originalImage, data.faceBoundingBox); }
        catch (e) { console.error("Auto Crop Failed:", e); }
        finally { setIsCropping(false); }
      }
    }

    const skinToneId = data.skinTone < 20 ? 'porcelain' : data.skinTone < 40 ? 'fair' : data.skinTone < 60 ? 'natural' : data.skinTone < 80 ? 'tanned' : 'deep';
    const hairLen = (data.hairLength === 'short' ? 'bob' : data.hairLength === 'medium' ? 'medium' : 'long') as any;
    const hairTex = (data.hairTexture === 'straight' ? 'straight' : 's_curl') as any;

    const analyzedFeatures = { ...INITIAL_FEATURES, eyeSize: data.eyeSize, canthalTilt: data.eyeTilt, noseBridge: data.noseBridge, jawShape: data.jawShape, lipThickness: data.lipFullness, noseWidth: data.noseWidth ?? 50, faceWidth: data.faceWidth ?? 50, cheekboneHeight: data.cheekboneHeight ?? 50 };
    const analyzedSkin = { ...state.skin, tone: skinToneId, skinAge: data.skinAge ?? 20 };
    const analyzedHair = { ...state.hair, hairLength: hairLen, hairTexture: hairTex };

    setState(prev => ({
      ...prev, baseImage: finalBaseImage, features: analyzedFeatures, skin: analyzedSkin, hair: analyzedHair,
      baseline: { features: analyzedFeatures, skin: analyzedSkin, hair: { hairLength: hairLen, hairTexture: hairTex } }
    }));
  };

  const resetCategory = useCallback((category: 'face' | 'skin' | 'hair' | 'makeup') => {
    setState(prev => {
      const newState = { ...prev };
      const bl = prev.baseline;
      switch (category) {
        case 'face': newState.features = { ...INITIAL_FEATURES, ...(bl?.features || {}) }; newState.makeup = { ...prev.makeup, eyebrowStyle: INITIAL_MAKEUP.eyebrowStyle, eyelinerStyle: INITIAL_MAKEUP.eyelinerStyle, eyelashStyle: INITIAL_MAKEUP.eyelashStyle }; break;
        case 'skin': newState.skin = { ...prev.skin, tone: bl?.skin?.tone || 'natural', skinAge: bl?.skin?.skinAge || 20, glowIntensity: 50, blemishIntensity: 10, texture: ['Smooth'] }; break;
        case 'hair': newState.hair = { ...INITIAL_HAIR, hairLength: bl?.hair?.hairLength || INITIAL_HAIR.hairLength, hairTexture: bl?.hair?.hairTexture || INITIAL_HAIR.hairTexture }; break;
        case 'makeup': newState.makeup = { ...INITIAL_MAKEUP, eyebrowStyle: prev.makeup.eyebrowStyle, eyelinerStyle: prev.makeup.eyelinerStyle, eyelashStyle: prev.makeup.eyelashStyle }; break;
      }
      return newState;
    });
  }, []);

  const handleGenerate = async () => {
    try {
      setIsGenerating(true); setError(null);
      const result = await generateBeautyImage(state);
      if (result) setGeneratedImage(result);
      else setError("Synthesis failed.");
    } catch (err: any) { setError(err.message || "An error occurred."); }
    finally { setIsGenerating(false); }
  };

  const handleDownload = () => {
    if (!generatedImage) return;
    const link = document.createElement('a'); link.href = generatedImage; link.download = `BeautySynth_PRO_2K_${Date.now()}.png`;
    document.body.appendChild(link); link.click(); document.body.removeChild(link);
  };

  const handleUseAsBase = () => {
    if (!generatedImage) return;
    updateState({ baseImage: generatedImage, baseline: undefined }); setGeneratedImage(null); setIsComparing(false);
  };

  const updateState = (updates: Partial<BeautyState>) => { setState(prev => ({ ...prev, ...updates })); };

  const calculateAspectRatio = (img: HTMLImageElement): any => {
    const ratio = img.width / img.height;
    const options = [ { label: "1:1", value: 1 }, { label: "3:4", value: 0.75 }, { label: "4:3", value: 1.33 }, { label: "9:16", value: 0.5625 }, { label: "16:9", value: 1.777 } ];
    return options.reduce((prev, curr) => Math.abs(curr.value - ratio) < Math.abs(prev.value - ratio) ? curr : prev).label;
  };

  const onFileUpload = (type: any) => (e: any) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = reader.result as string;
        if (type === 'base') {
          const img = new Image();
          img.onload = async () => {
            updateState({ baseImage: base64String, aspectRatio: calculateAspectRatio(img), baseline: undefined });
            try {
              setIsAnalyzing(true);
              const analysis = await analyzeImageAttributes(base64String);
              await applyAnalysis(analysis, base64String);
            } catch (err) { setError("AI analysis failed."); }
            finally { setIsAnalyzing(false); }
          };
          img.src = base64String;
        } else {
          updateState({ referenceImages: { ...state.referenceImages, [type]: base64String } });
        }
      };
      reader.readAsDataURL(file);
    }
  };

  const currentPrompt = useMemo(() => generateBeautyPrompt(state), [state]);
  if (needsKey) return <ApiKeyModal onComplete={() => setNeedsKey(false)} />;

  return (
    <div className="flex flex-col h-screen bg-black overflow-hidden text-zinc-100">
      <header className="h-16 border-b border-zinc-900 flex items-center justify-between px-6 bg-zinc-950/80 backdrop-blur-xl z-50">
        <div className="flex items-center gap-3"><div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center shadow-lg"><Sparkles className="w-6 h-6 text-white" /></div><div><h1 className="text-lg font-bold">BeautySynth <span className="text-indigo-500">PRO</span></h1><p className="text-[10px] text-zinc-500 font-bold uppercase tracking-widest">Expert Medical Facial Synthesis</p></div></div>
        <button onClick={handleGenerate} disabled={isGenerating || !state.baseImage} className={`flex items-center gap-2 px-8 py-2.5 rounded-full font-bold transition-all ${isGenerating || !state.baseImage ? 'bg-zinc-900 text-zinc-600' : 'bg-indigo-600 hover:bg-indigo-500 text-white shadow-xl shadow-indigo-600/20'}`}>{isGenerating ? <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" /> : <Zap className="w-4 h-4" />}{isGenerating ? 'Synthesizing...' : 'Generate Synthesis'}</button>
      </header>
      <main className="flex flex-1 overflow-hidden">
        <StudioSidebar state={state} updateState={updateState} onRefUpload={onFileUpload} onResetCategory={resetCategory} />
        <div className="flex-1 p-6 flex flex-col gap-6 overflow-hidden bg-zinc-950">
          {error && <div className="bg-red-500/10 border border-red-500/20 text-red-400 p-3 rounded-xl flex items-center justify-between text-sm shrink-0"><span>{error}</span><button onClick={() => setError(null)}>✕</button></div>}
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 flex-1 min-h-0">
            <div className="bg-zinc-900/50 border border-zinc-800/50 rounded-3xl overflow-hidden flex flex-col relative shadow-inner">
              <div className="p-4 border-b border-zinc-800/50 flex justify-between items-center bg-zinc-900/30"><h3 className="text-[10px] font-bold text-zinc-500 uppercase tracking-widest">Input: Base Image</h3><div className="flex items-center gap-2">{isAnalyzing && <span className="text-[10px] text-indigo-400 animate-pulse"><Search className="w-3 h-3 inline mr-1" /> Analyzing...</span>}{isCropping && <span className="text-[10px] text-emerald-400 animate-pulse"><Scissors className="w-3 h-3 inline mr-1" /> Cropping...</span>}{state.baseImage && <button onClick={() => updateState({ baseImage: null })} className="text-zinc-600 hover:text-red-400"><Trash2 className="w-4 h-4" /></button>}</div></div>
              <div className="flex-1 flex items-center justify-center relative bg-black">
                {state.baseImage ? <img src={state.baseImage} className={`max-w-full max-h-full object-contain ${isAnalyzing ? 'opacity-40 grayscale' : 'opacity-100'}`} alt="Base" /> : <label className="cursor-pointer flex flex-col items-center gap-4"><Upload className="w-8 h-8 text-zinc-600" /><span className="text-zinc-500 text-sm">Upload Base Image</span><input type="file" className="hidden" accept="image/*" onChange={onFileUpload('base')} /></label>}
              </div>
            </div>
            <div className="bg-zinc-900/50 border border-zinc-800/50 rounded-3xl overflow-hidden flex flex-col relative shadow-2xl">
              <div className="p-4 border-b border-zinc-800/50 flex justify-between items-center bg-zinc-900/30"><h3 className="text-[10px] font-bold text-zinc-500 uppercase tracking-widest">Synthesis Result</h3><div className="flex gap-2">{generatedImage && <><button onClick={handleUseAsBase} className="text-[10px] text-indigo-400 flex items-center gap-2 px-3 py-1 rounded-full bg-indigo-500/10 border border-indigo-500/20"><RefreshCcw className="w-3 h-3" /> Use as Base</button><button onClick={handleDownload} className="text-[10px] text-emerald-400 flex items-center gap-2 px-3 py-1 rounded-full bg-emerald-500/10 border border-emerald-500/20"><Download className="w-3 h-3" /> Download</button><button onMouseDown={() => setIsComparing(true)} onMouseUp={() => setIsComparing(false)} onMouseLeave={() => setIsComparing(false)} className="text-[10px] text-zinc-400 flex items-center gap-2 px-3 py-1 rounded-full bg-zinc-500/10 border border-zinc-500/20 select-none">{isComparing ? <EyeOff className="w-3 h-3" /> : <Eye className="w-3 h-3" />} Compare</button></>}</div></div>
              <div className="flex-1 bg-black relative flex items-center justify-center overflow-hidden">
                <PreviewCanvas image={isComparing ? state.baseImage : generatedImage} loading={isGenerating} onDownload={handleDownload} state={state} baseImage={state.baseImage} />
                {isComparing && <div className="absolute top-4 left-4 px-3 py-1 bg-black/80 text-[10px] font-bold text-white uppercase tracking-widest rounded-full">Original</div>}
              </div>
            </div>
          </div>
          <div className="bg-zinc-900/50 border border-zinc-800/50 rounded-3xl p-4 flex flex-col gap-2 shrink-0 h-28 overflow-hidden"><h3 className="text-[10px] font-bold text-zinc-500 uppercase tracking-widest flex items-center gap-2"><Zap className="w-3 h-3 text-indigo-500" /> Targeted Synthesis Prompt Preview</h3><div className="flex-1 overflow-y-auto text-[11px] text-zinc-400 font-mono bg-black/30 p-3 rounded-xl border border-zinc-800/50">{currentPrompt}</div></div>
        </div>
      </main>
      <style>{`@keyframes scan { from { transform: translateX(-100%); } to { transform: translateX(300%); } }`}</style>
    </div>
  );
};

export default App;

import React, { useMemo } from 'react';
